const CAT_PREFIX = { "Tanato": "TAN", "Cozinha": "COZ", "Limpeza": "LIM", "Funerária": "FUN" };

function buildSeedProducts() {
  const counters = {};
  return RAW_TOLEDO.map(([name, unit, category, quantity]) => {
    counters[category] = (counters[category] || 0) + 1;
    const sku = `${CAT_PREFIX[category]}-${String(counters[category]).padStart(3, "0")}`;
    return {
      id: `p-${sku}`,
      name,
      sku,
      category,
      unit,
      quantity,
      minStock: 5,
      unitPrice: 0,
      city: "Toledo",
      orderQty: 0,
    };
  });
}

// Catálogo base (SKU, nome, categoria, unidade) derivado do estoque de Toledo,
// usado só para saber quais itens existem — sem os números de estoque.
function baseCatalog() {
  const counters = {};
  return RAW_TOLEDO.map(([name, unit, category]) => {
    counters[category] = (counters[category] || 0) + 1;
    const sku = `${CAT_PREFIX[category]}-${String(counters[category]).padStart(3, "0")}`;
    return { sku, name, category, unit };
  });
}

function citySlug(cityName) {
  return cityName.normalize("NFD").replace(/[̀-ͯ]/g, "").toLowerCase();
}

// Gera os mesmos itens do catálogo de Toledo para outra filial, com
// quantidade 0 (sem estoque informado) — cada item usado para pedidos,
// mínimo e movimentações a partir do zero.
function buildCityCatalogProducts(cityName) {
  return baseCatalog().map(({ sku, name, category, unit }) => ({
    id: `p-${citySlug(cityName)}-${sku}`,
    name,
    sku,
    category,
    unit,
    quantity: 0,
    minStock: 5,
    unitPrice: 0,
    city: cityName,
    orderQty: 0,
  }));
}

// Garante que todas as filiais (exceto Toledo) tenham os itens do catálogo
// base cadastrados, sem sobrescrever produtos já existentes (comparados por
// SKU + filial) nem herdar quantidade de estoque.
function replicateCatalogToOtherCities(products) {
  let next = products;
  CITIES.filter((c) => c !== "Toledo").forEach((c) => {
    const existingSkus = new Set(next.filter((p) => p.city === c).map((p) => p.sku));
    const toAdd = buildCityCatalogProducts(c).filter((p) => !existingSkus.has(p.sku));
    if (toAdd.length > 0) next = [...next, ...toAdd];
  });
  return next;
}

function fmtBRL(v) {
  return v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}
function fmtDate(iso) {
  return new Date(iso).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit" });
}
function fmtDateTime(iso) {
  if (!iso) return "";
  return new Date(iso).toLocaleString("pt-BR", { day: "2-digit", month: "2-digit", hour: "2-digit", minute: "2-digit" });
}
function uid() {
  return Math.random().toString(36).slice(2, 10);
}

function normalizeSku(sku) {
  return (sku || "").trim().toLowerCase();
}

// Agrupa produtos (de qualquer filial) por SKU normalizado e devolve só os
// grupos com um problema de verdade: o mesmo SKU usado por produtos com
// nomes diferentes (colisão), ou repetido mais de uma vez na MESMA filial.
// O mesmo SKU com o mesmo nome em filiais diferentes é o comportamento
// normal da replicação de catálogo entre filiais, então não é acusado.
function findDuplicateSkus(products) {
  const bySku = {};
  products.forEach((p) => {
    const key = normalizeSku(p.sku);
    if (!key) return;
    if (!bySku[key]) bySku[key] = [];
    bySku[key].push(p);
  });

  return Object.values(bySku).filter((group) => {
    const distinctNames = new Set(group.map((p) => p.name.trim().toLowerCase()));
    const seenCityName = new Set();
    let sameCityDuplicate = false;
    group.forEach((p) => {
      const key = `${p.city}::${p.name.trim().toLowerCase()}`;
      if (seenCityName.has(key)) sameCityDuplicate = true;
      seenCityName.add(key);
    });
    return distinctNames.size > 1 || sameCityDuplicate;
  });
}

// Sugere o próximo SKU sequencial pro setor escolhido (ex.: Cozinha →
// COZ-00x), olhando o maior número já usado nesse prefixo entre todos os
// produtos cadastrados (qualquer filial).
function suggestSku(category, products) {
  const prefix = CAT_PREFIX[category];
  if (!prefix) return "";
  const re = new RegExp(`^${prefix}-(\\d+)$`, "i");
  let max = 0;
  products.forEach((p) => {
    const m = re.exec((p.sku || "").trim());
    if (m) max = Math.max(max, parseInt(m[1], 10));
  });
  return `${prefix}-${String(max + 1).padStart(3, "0")}`;
}

// Resolve conflitos reais de SKU (mesmo SKU usado por produtos com nomes
// diferentes, ou duas linhas iguais na mesma filial), usando Toledo como
// referência: quando o SKU também existe em Toledo, o produto de Toledo
// mantém esse SKU e os outros ganham um SKU novo, sem conflito. Sem Toledo
// no grupo, mantém o primeiro produto encontrado e renomeia os demais.
// Produtos com o mesmo SKU e o mesmo nome em filiais diferentes (replicação
// normal do catálogo) não são mexidos.
function resolveSkuConflicts(products) {
  const bySku = {};
  products.forEach((p) => {
    const key = normalizeSku(p.sku);
    if (!key) return;
    if (!bySku[key]) bySku[key] = [];
    bySku[key].push(p);
  });

  // Números de SKU já em uso por prefixo, pra nunca sugerir algo que colida
  // com um SKU existente (ou com outra renomeação feita nesta mesma passada).
  const usedByPrefix = {};
  products.forEach((p) => {
    const m = /^([A-Za-z]+)-(\d+)$/.exec((p.sku || "").trim());
    if (m) {
      const prefix = m[1].toUpperCase();
      usedByPrefix[prefix] = usedByPrefix[prefix] || new Set();
      usedByPrefix[prefix].add(parseInt(m[2], 10));
    }
  });

  function nextSkuFor(category) {
    const prefix = CAT_PREFIX[category] || "PRD";
    const used = usedByPrefix[prefix] || new Set();
    let n = 1;
    while (used.has(n)) n++;
    used.add(n);
    usedByPrefix[prefix] = used;
    return `${prefix}-${String(n).padStart(3, "0")}`;
  }

  const renames = {}; // id -> novo sku

  Object.values(bySku).forEach((group) => {
    const byName = {};
    group.forEach((p) => {
      const key = p.name.trim().toLowerCase();
      (byName[key] = byName[key] || []).push(p);
    });
    const distinctNames = Object.keys(byName);

    const seenCityName = new Set();
    let hasSameCityDuplicate = false;
    group.forEach((p) => {
      const key = `${p.city}::${p.name.trim().toLowerCase()}`;
      if (seenCityName.has(key)) hasSameCityDuplicate = true;
      seenCityName.add(key);
    });

    if (distinctNames.length <= 1 && !hasSameCityDuplicate) return; // ok, replicação normal entre filiais

    // Escolhe o "dono" do SKU original: o nome que tiver produto em
    // Toledo, ou o primeiro nome encontrado se nenhum for de Toledo.
    let ownerNameKey = distinctNames.find((key) => byName[key].some((p) => p.city === "Toledo"));
    if (!ownerNameKey) ownerNameKey = distinctNames[0];

    // Dentro do nome "dono", mantém só o primeiro produto de cada filial
    // com o SKU original — linhas redundantes na mesma filial também
    // ganham SKU novo.
    const ownerCitySeen = new Set();
    group.forEach((p) => {
      const nameKey = p.name.trim().toLowerCase();
      const isOwnerName = nameKey === ownerNameKey;
      const duplicateInSameCity = isOwnerName && ownerCitySeen.has(p.city);
      if (isOwnerName) ownerCitySeen.add(p.city);

      if (!isOwnerName || duplicateInSameCity) {
        renames[p.id] = nextSkuFor(p.category);
      }
    });
  });

  if (Object.keys(renames).length === 0) return products;
  return products.map((p) => (renames[p.id] ? { ...p, sku: renames[p.id] } : p));
}

// Alinha SKU, unidade e setor dos produtos das outras filiais com o produto
// de mesmo nome em Toledo (fonte da verdade do catálogo). Corrige tanto
// divergências antigas (ex.: "Chá" virou CX em Toledo e UN em Palotina) como
// SKUs que tiveram que ser trocados manualmente por causa de uma validação
// antiga bugada. Quantidade, mínimo, preço e pedido de cada filial não são
// mexidos — só os campos "de catálogo".
function alignCatalogWithToledo(products) {
  const toledoByName = {};
  products.forEach((p) => {
    if (p.city === "Toledo") {
      toledoByName[p.name.trim().toLowerCase()] = p;
    }
  });

  let changed = false;
  const next = products.map((p) => {
    if (p.city === "Toledo") return p;
    const ref = toledoByName[p.name.trim().toLowerCase()];
    if (!ref) return p;
    if (p.sku === ref.sku && p.unit === ref.unit && p.category === ref.category) return p;
    changed = true;
    return { ...p, sku: ref.sku, unit: ref.unit, category: ref.category };
  });

  return changed ? next : products;
}

export default function ControleEstoque() {
  const { userName } = useAuth();
  const [products, setProducts] = useState(null);
  const [movements, setMovements] = useState(null);
  const [ready, setReady] = useState(false);
  const [tab, setTab] = useState("dashboard");
  const [search, setSearch] = useState("");
  const [catFilter, setCatFilter] = useState("Todos");
  const [city, setCity] = useState("Toledo");
  const [productModal, setProductModal] = useState(null);
  const [moveModal, setMoveModal] = useState(null);
  const [moveEditModal, setMoveEditModal] = useState(null);
  const [confirmDeleteMovement, setConfirmDeleteMovement] = useState(null);
  const [importModal, setImportModal] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(null);
  const [convertModal, setConvertModal] = useState(null);
  const [printTarget, setPrintTarget] = useState(null); // null | { city: cityName | 'all', source: 'matriz' | 'local' }
  const [showChangelog, setShowChangelog] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [lastEdited, setLastEdited] = useState(null); // { by, at } | null

  useEffect(() => {
    if (!printTarget) return;
    let cancelled = false;
    let raf1 = null;
    let raf2 = null;

    const doPrint = () => {
      if (cancelled) return;
      window.print();
    };

    // Só dispara a impressão depois que as imagens da folha impressa (logos)
    // terminarem de carregar. Sem isso, o navegador pode abrir o diálogo de
    // impressão com o layout ainda incompleto (logo grande em base64 ainda
    // decodificando), gerando uma primeira página em branco e empurrando o
    // conteúdo real para a página seguinte.
    const waitForImagesThenPrint = () => {
      if (cancelled) return;
      const sheet = document.querySelector(".print-sheet");
      const imgs = sheet ? Array.from(sheet.querySelectorAll("img")) : [];
      const pending = imgs.filter((img) => !img.complete);

      const scheduleAfterPaint = () => {
        // dupla rAF garante que o navegador já pintou o layout final
        // antes de abrirmos o diálogo de impressão.
        raf1 = requestAnimationFrame(() => {
          raf2 = requestAnimationFrame(doPrint);
        });
      };

      if (pending.length === 0) {
        scheduleAfterPaint();
        return;
      }
      let remaining = pending.length;
      const onSettle = () => {
        remaining -= 1;
        if (remaining === 0) scheduleAfterPaint();
      };
      pending.forEach((img) => {
        img.addEventListener("load", onSettle, { once: true });
        img.addEventListener("error", onSettle, { once: true });
      });
    };

    // Pequeno atraso inicial para garantir que o React já montou a folha de
    // impressão com o novo target antes de procurarmos as imagens.
    const t = setTimeout(waitForImagesThenPrint, 30);
    const handleAfter = () => setPrintTarget(null);
    window.addEventListener("afterprint", handleAfter);
    return () => {
      cancelled = true;
      clearTimeout(t);
      if (raf1) cancelAnimationFrame(raf1);
      if (raf2) cancelAnimationFrame(raf2);
      window.removeEventListener("afterprint", handleAfter);
    };
  }, [printTarget]);

  useEffect(() => {
    (async () => {
      try {
        const res = await storage.get("estoque-data-v2");
        let raw = res && res.value;

        // Se o Supabase está configurado mas ainda não tem nada salvo (banco
        // novo), aproveita os dados que já existiam no localStorage deste
        // navegador — quem já vinha usando o app antes de configurar o
        // Supabase não perde o estoque que já tinha digitado — e sobe eles
        // pro banco compartilhado.
        let migratingFromLocal = false;
        if (!raw && isSupabaseConfigured) {
          const legacy = readLegacyLocalStorage("estoque-data-v2");
          if (legacy) {
            raw = legacy;
            migratingFromLocal = true;
          }
        }

        if (raw) {
          const parsed = JSON.parse(raw);
          let migrated = (parsed.products || []).map((p) => ({ orderQty: 0, ...p }));
          const movs = parsed.movements || [];
          let needsSave = migratingFromLocal;
          // Replica o catálogo base de Toledo (sem estoque) para as demais
          // filiais uma única vez — só roda de novo se ainda não tiver rodado.
          if (!parsed.catalogReplicated) {
            migrated = replicateCatalogToOtherCities(migrated);
            needsSave = true;
          }
          // Resolve conflitos de SKU (mesmo código usado por produtos
          // diferentes) uma única vez, usando Toledo como referência —
          // também só roda se ainda não tiver rodado.
          if (!parsed.skuConflictsResolved) {
            migrated = resolveSkuConflicts(migrated);
            needsSave = true;
          }
          // Alinha SKU, unidade e setor dos produtos das outras filiais com
          // o correspondente em Toledo (por nome) — uma única vez.
          if (!parsed.catalogAligned) {
            migrated = alignCatalogWithToledo(migrated);
            needsSave = true;
          }
          setProducts(migrated);
          setMovements(movs);
          if (parsed.lastEditedBy) setLastEdited({ by: parsed.lastEditedBy, at: parsed.lastEditedAt });
          if (needsSave) {
            await storage.set(
              "estoque-data-v2",
              JSON.stringify({
                products: migrated,
                movements: movs,
                catalogReplicated: true,
                skuConflictsResolved: true,
                catalogAligned: true,
                lastEditedBy: parsed.lastEditedBy,
                lastEditedAt: parsed.lastEditedAt,
              })
            );
          }
        } else {
          const seeded = alignCatalogWithToledo(replicateCatalogToOtherCities(buildSeedProducts()));
          setProducts(seeded);
          setMovements([]);
          await storage.set(
            "estoque-data-v2",
            JSON.stringify({
              products: seeded,
              movements: [],
              catalogReplicated: true,
              skuConflictsResolved: true,
              catalogAligned: true,
            })
          );
        }
      } catch (e) {
        setProducts(buildSeedProducts());
        setMovements([]);
      }
      setReady(true);
    })();
  }, []);

  // Mantém a tela sincronizada quase em tempo real com o que a outra pessoa
  // salvar (via Supabase Realtime) — reduz bastante a janela em que duas
  // pessoas mexendo ao mesmo tempo poderiam sobrescrever uma a outra, mas
  // não elimina o risco por completo: se as duas editarem o mesmíssimo
  // produto/movimentação dentro de poucos segundos uma da outra, quem salvar
  // por último ainda prevalece. Sem Supabase configurado, isso não faz nada.
  useEffect(() => {
    if (!ready) return;
    const unsubscribe = storage.subscribe("estoque-data-v2", (rawValue) => {
      try {
        const parsed = JSON.parse(rawValue);
        setProducts((parsed.products || []).map((p) => ({ orderQty: 0, ...p })));
        setMovements(parsed.movements || []);
        if (parsed.lastEditedBy) setLastEdited({ by: parsed.lastEditedBy, at: parsed.lastEditedAt });
      } catch (e) {
        console.error("Falha ao processar atualização em tempo real", e);
      }
    });
    return unsubscribe;
  }, [ready]);

  async function persist(nextProducts, nextMovements) {
    setProducts(nextProducts);
    setMovements(nextMovements);
    const editedAt = new Date().toISOString();
    setLastEdited({ by: userName, at: editedAt });
    try {
      await storage.set(
        "estoque-data-v2",
        JSON.stringify({
          products: nextProducts,
          movements: nextMovements,
          catalogReplicated: true,
          skuConflictsResolved: true,
          catalogAligned: true,
          lastEditedBy: userName,
          lastEditedAt: editedAt,
        })
      );
    } catch (e) {
      console.error("Falha ao salvar", e);
    }
  }

  // Baixa uma cópia completa do estoque (produtos + movimentações de todas
  // as filiais) num arquivo .json — serve como backup fora do banco, caso
  // algo seja apagado por engano ou o banco tenha algum problema. Pra
  // restaurar, é só guardar o arquivo; se um dia precisar, dá pra colar o
  // conteúdo de volta na tabela app_state do Supabase manualmente.
  function downloadBackup() {
    const payload = {
      exportedAt: new Date().toISOString(),
      exportedBy: userName,
      products,
      movements,
    };
    downloadTextFile(`backup-estoque-${new Date().toISOString().slice(0, 10)}.json`, JSON.stringify(payload, null, 2));
  }

  function saveProduct(p) {
    const now = new Date().toISOString();
    if (p.id) {
      const stamped = { ...p, updatedBy: userName, updatedAt: now };
      persist(products.map((x) => (x.id === p.id ? stamped : x)), movements);
    } else {
      const newP = { ...p, id: uid(), createdBy: userName, createdAt: now, updatedBy: userName, updatedAt: now };
      persist([newP, ...products], movements);
    }
    setProductModal(null);
  }

  // Não apaga de verdade — marca como "deleted" e preserva o histórico de
  // movimentações do item, pra dar pra desfazer um apagão por engano na
  // Lixeira (aba Produtos). O produto some das telas normais, mas continua
  // no banco.
  function deleteProduct(id) {
    const now = new Date().toISOString();
    const nextProducts = products.map((p) =>
      p.id === id ? { ...p, deleted: true, deletedBy: userName, deletedAt: now } : p
    );
    persist(nextProducts, movements);
    setConfirmDelete(null);
  }

  function restoreProduct(id) {
    const nextProducts = products.map((p) =>
      p.id === id ? { ...p, deleted: false, deletedBy: null, deletedAt: null } : p
    );
    persist(nextProducts, movements);
  }

  // Converte um item (identificado pelo nome) de uma unidade "embalada"
  // (CX/PCT/FARDO) para UN em TODAS as filiais de uma vez, usando o fator
  // informado (quantas unidades individuais tem em cada embalagem). Estoque,
  // mínimo, preço unitário e quantidade a pedir são recalculados; o SKU não
  // muda. Sem isso, cada filial poderia acabar com uma unidade diferente
  // pro mesmo item.
  function convertProductUnit(productName, factor) {
    const key = productName.trim().toLowerCase();
    const nextProducts = products.map((p) => {
      if (p.name.trim().toLowerCase() !== key) return p;
      return {
        ...p,
        unit: "UN",
        quantity: Math.round(p.quantity * factor),
        minStock: Math.round(p.minStock * factor),
        unitPrice: factor > 0 ? Math.round((p.unitPrice / factor) * 100) / 100 : p.unitPrice,
        orderQty: Math.round((Number(p.orderQty) || 0) * factor),
      };
    });
    persist(nextProducts, movements);
    setConvertModal(null);
  }

  function addMovement(mv) {
    const product = products.find((p) => p.id === mv.productId);
    if (!product) return;
    const delta = mv.type === "entrada" ? mv.quantity : -mv.quantity;
    const nextProducts = products.map((p) =>
      p.id === mv.productId ? { ...p, quantity: Math.max(0, p.quantity + delta) } : p
    );
    const newMv = { ...mv, id: uid(), city: product.city, date: new Date().toISOString(), createdBy: userName };
    persist(nextProducts, [newMv, ...movements]);
    setMoveModal(null);
  }

  // Transfere estoque de um produto de uma filial pra outra: dá baixa no
  // produto de origem, soma no produto correspondente na filial de destino
  // — criando esse produto no destino se ainda não existir — e registra uma
  // saída + uma entrada vinculadas (mesmo transferId).
  //
  // Só reaproveita um produto já existente no destino se SKU **e** nome
  // baterem ao mesmo tempo. SKU sozinho não é garantia (pode ter sido
  // reaproveitado manualmente em outro item), então qualquer divergência
  // faz o app criar um produto novo no destino em vez de arriscar somar
  // estoque num item errado.
  function transferStock({ fromCity, toCity, product, quantity, packageInfo }) {
    const now = new Date().toISOString();
    const transferId = uid();

    const existingDest = products.find(
      (p) =>
        p.city === toCity &&
        p.sku === product.sku &&
        p.name.trim().toLowerCase() === product.name.trim().toLowerCase()
    );
    const destId = existingDest ? existingDest.id : uid();

    let nextProducts = products.map((p) => {
      if (p.id === product.id) {
        return { ...p, quantity: Math.max(0, p.quantity - quantity) };
      }
      if (existingDest && p.id === existingDest.id) {
        return { ...p, quantity: p.quantity + quantity };
      }
      return p;
    });

    if (!existingDest) {
      nextProducts = [
        {
          id: destId,
          name: product.name,
          sku: product.sku,
          category: product.category,
          unit: product.unit,
          quantity,
          minStock: product.minStock,
          unitPrice: product.unitPrice,
          city: toCity,
          orderQty: 0,
        },
        ...nextProducts,
      ];
    }

    const outMovement = {
      id: uid(),
      type: "saida",
      productId: product.id,
      quantity,
      note: `Transferência para ${toCity}`,
      city: fromCity,
      date: now,
      transferId,
      createdBy: userName,
      ...(packageInfo || {}),
    };
    const inMovement = {
      id: uid(),
      type: "entrada",
      productId: destId,
      quantity,
      note: `Transferência de ${fromCity}`,
      city: toCity,
      date: now,
      transferId,
      createdBy: userName,
      ...(packageInfo || {}),
    };

    persist(nextProducts, [inMovement, outMovement, ...movements]);
  }

  // Edita uma movimentação já registrada, ajustando o estoque pra refletir
  // a diferença. Se ela for parte de uma transferência (tem transferId), só
  // a quantidade e a observação podem mudar, e a quantidade é ajustada nos
  // dois lados (origem e destino) junto, pra não desbalancear a transferência.
  function editMovement(original, updates) {
    const linked = original.transferId
      ? movements.find((m) => m.transferId === original.transferId && m.id !== original.id)
      : null;
    const newQty = Number(updates.quantity);

    if (linked) {
      const deltaOut = newQty - original.quantity;
      const nextProducts = products.map((p) => {
        if (p.id === original.productId) {
          const delta = original.type === "saida" ? -deltaOut : deltaOut;
          return { ...p, quantity: Math.max(0, p.quantity + delta) };
        }
        if (p.id === linked.productId) {
          const delta = linked.type === "saida" ? -deltaOut : deltaOut;
          return { ...p, quantity: Math.max(0, p.quantity + delta) };
        }
        return p;
      });
      const nextMovements = movements.map((m) => {
        if (m.id === original.id) return { ...m, quantity: newQty, note: updates.note, editedBy: userName, editedAt: new Date().toISOString() };
        if (m.id === linked.id) return { ...m, quantity: newQty };
        return m;
      });
      persist(nextProducts, nextMovements);
    } else {
      let nextProducts = products.map((p) => {
        if (p.id !== original.productId) return p;
        const undo = original.type === "entrada" ? -original.quantity : original.quantity;
        return { ...p, quantity: Math.max(0, p.quantity + undo) };
      });
      nextProducts = nextProducts.map((p) => {
        if (p.id !== updates.productId) return p;
        const apply = updates.type === "entrada" ? newQty : -newQty;
        return { ...p, quantity: Math.max(0, p.quantity + apply) };
      });
      const nextMovements = movements.map((m) =>
        m.id === original.id
          ? {
              ...m,
              productId: updates.productId,
              type: updates.type,
              quantity: newQty,
              note: updates.note,
              editedBy: userName,
              editedAt: new Date().toISOString(),
              ...(updates.hasOwnProperty("source") ? { source: updates.source } : {}),
            }
          : m
      );
      persist(nextProducts, nextMovements);
    }
    setMoveEditModal(null);
  }

  // Apaga uma movimentação e desfaz o efeito dela no estoque. Se ela for
  // parte de uma transferência, apaga e desfaz os dois lados juntos.
  function deleteMovement(mv) {
    const linked = mv.transferId
      ? movements.find((m) => m.transferId === mv.transferId && m.id !== mv.id)
      : null;

    function undoOne(list, m) {
      return list.map((p) => {
        if (p.id !== m.productId) return p;
        const undo = m.type === "entrada" ? -m.quantity : m.quantity;
        return { ...p, quantity: Math.max(0, p.quantity + undo) };
      });
    }

    let nextProducts = undoOne(products, mv);
    if (linked) nextProducts = undoOne(nextProducts, linked);

    const idsToRemove = linked ? [mv.id, linked.id] : [mv.id];
    const nextMovements = movements.filter((m) => !idsToRemove.includes(m.id));

    persist(nextProducts, nextMovements);
    setConfirmDeleteMovement(null);
    setMoveEditModal(null);
  }

  // rows: [{ productId?, newProduct?, quantity, note }]
  // Se productId existir, soma a quantidade a um produto já cadastrado.
  // Se newProduct existir, cria o produto antes de dar entrada.
  function importMovements(rows) {
    let nextProducts = [...products];
    const now = new Date().toISOString();
    const newMovs = [];

    rows.forEach((row) => {
      let productId = row.productId;
      if (!productId && row.newProduct) {
        const newP = { ...row.newProduct, id: uid(), orderQty: 0 };
        nextProducts = [newP, ...nextProducts];
        productId = newP.id;
      }
      if (!productId) return;
      nextProducts = nextProducts.map((p) =>
        p.id === productId ? { ...p, quantity: Math.max(0, p.quantity + row.quantity) } : p
      );
      const product = nextProducts.find((p) => p.id === productId);
      newMovs.push({
        id: uid(),
        productId,
        type: "entrada",
        quantity: row.quantity,
        note: row.note || "Importado de planilha",
        city: product.city,
        date: now,
        createdBy: userName,
      });
    });

    persist(nextProducts, [...newMovs, ...movements]);
    setImportModal(false);
  }

  function updateOrderQuantities(updates) {
    // updates: { [productId]: { qty, unit, packageQty, factor } }
    const nextProducts = products.map((p) => {
      if (!updates.hasOwnProperty(p.id)) return p;
      const d = updates[p.id];
      const isPackaged = d.unit && d.unit !== p.unit;
      return {
        ...p,
        orderQty: d.qty,
        orderPackageUnit: isPackaged ? d.unit : null,
        orderPackageQty: isPackaged ? Number(d.packageQty) || 0 : null,
        orderUnitsPerPackage: isPackaged ? Number(d.factor) || 0 : null,
      };
    });
    persist(nextProducts, movements);
  }

  // Marca se um produto deve entrar no pedido enviado à matriz (Umuarama)
  // ou se é item de compra local — usado pra filtrar o que sai no PDF/texto
  // do pedido. Persiste na hora, sem depender do botão "Salvar pedido".
  function updateProductOrderSource(productId, source) {
    const nextProducts = products.map((p) => (p.id === productId ? { ...p, orderSource: source } : p));
    persist(nextProducts, movements);
  }

  // Redefine a origem de todos os produtos de uma filial de volta pra
  // "matriz" de uma vez — evita ter que clicar item por item quando só
  // algumas exceções tinham virado compra local.
  function resetOrderSourceToMatriz(cityName) {
    const nextProducts = products.map((p) => (p.city === cityName ? { ...p, orderSource: "matriz" } : p));
    persist(nextProducts, movements);
  }

  // "Apagar" um produto só marca deleted:true (veja deleteProduct) pra dar
  // pra restaurar na Lixeira — por isso a maioria das telas usa as listas
  // "ativas" abaixo, que escondem os produtos apagados. A exceção é a
  // Movimentações (cityProductsForHistory), que precisa continuar mostrando
  // o nome/unidade certos mesmo pra um produto já apagado, senão o
  // histórico antigo vira "Produto removido" sem necessidade.
  const activeProducts = useMemo(() => (products || []).filter((p) => !p.deleted), [products]);
  const cityProducts = useMemo(() => activeProducts.filter((p) => p.city === city), [activeProducts, city]);
  const cityProductsForHistory = useMemo(() => (products || []).filter((p) => p.city === city), [products, city]);
  const cityMovements = useMemo(() => (movements || []).filter((m) => m.city === city), [movements, city]);

  const stats = useMemo(() => {
    if (!products) return null;
    const totalItems = cityProducts.reduce((s, p) => s + p.quantity, 0);
    const totalValue = cityProducts.reduce((s, p) => s + p.quantity * p.unitPrice, 0);
    const lowStock = cityProducts.filter((p) => p.quantity <= p.minStock);
    const now = new Date();
    const monthMoves = cityMovements.filter((m) => {
      const d = new Date(m.date);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
    return { totalItems, totalValue, lowStock, monthMovesCount: monthMoves.length };
  }, [products, cityProducts, cityMovements]);

  const byCategory = useMemo(() => {
    const map = {};
    cityProducts.forEach((p) => {
      if (!map[p.category]) map[p.category] = { category: p.category, quantidade: 0, valor: 0 };
      map[p.category].quantidade += p.quantity;
      map[p.category].valor += p.quantity * p.unitPrice;
    });
    return Object.values(map);
  }, [cityProducts]);

  const movementSeries = useMemo(() => {
    const days = [];
    const now = new Date();
    for (let i = 13; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const key = d.toISOString().slice(0, 10);
      days.push({ key, label: fmtDate(d.toISOString()), entradas: 0, saidas: 0 });
    }
    const dayMap = Object.fromEntries(days.map((d) => [d.key, d]));
    cityMovements.forEach((m) => {
      const key = m.date.slice(0, 10);
      if (dayMap[key]) {
        if (m.type === "entrada") dayMap[key].entradas += m.quantity;
        else dayMap[key].saidas += m.quantity;
      }
    });
    return days;
  }, [cityMovements]);

  const filteredProducts = useMemo(() => {
    return cityProducts.filter((p) => {
      const matchesSearch =
        p.name.toLowerCase().includes(search.toLowerCase()) ||
        p.sku.toLowerCase().includes(search.toLowerCase());
      const matchesCat = catFilter === "Todos" || p.category === catFilter;
      return matchesSearch && matchesCat;
    });
  }, [cityProducts, search, catFilter]);

  if (!ready || !products) {
    return (
      <div style={{ background: TOKENS.paper, minHeight: 400, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "Inter, sans-serif", color: TOKENS.charcoal }}>
        Carregando estoque…
      </div>
    );
  }

  return (
    <>
    <div className="no-print" style={{ background: TOKENS.paper, minHeight: 600, fontFamily: "'Inter', sans-serif", color: TOKENS.charcoal }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;700&family=Inter:wght@400;500;600&family=IBM+Plex+Mono:wght@400;500&display=swap');
        .est-tab { font-family: 'Space Grotesk', sans-serif; font-weight: 700; letter-spacing: 0.02em; cursor: pointer; user-select: none; transition: transform 0.15s ease; }
        .est-tab:hover { transform: translateY(-2px); }
        .est-mono { font-family: 'IBM Plex Mono', monospace; }
        .est-card { background: #fff; border: 1px solid ${TOKENS.line}; border-radius: 10px; }
        .est-btn { font-family: 'Inter', sans-serif; font-weight: 600; cursor: pointer; border: none; border-radius: 8px; padding: 9px 16px; font-size: 13px; display: inline-flex; align-items: center; gap: 6px; transition: opacity 0.15s ease; }
        .est-btn:hover { opacity: 0.88; }
        .est-input { font-family: 'Inter', sans-serif; border: 1px solid ${TOKENS.line}; border-radius: 8px; padding: 8px 10px; font-size: 13px; background: #fff; color: ${TOKENS.charcoal}; }
        .est-input:focus { outline: 2px solid ${TOKENS.teal}44; }
        table.est-table { width: 100%; border-collapse: collapse; font-size: 13px; }
        table.est-table th { text-align: left; font-family: 'Space Grotesk', sans-serif; font-size: 11px; letter-spacing: 0.06em; text-transform: uppercase; color: ${TOKENS.inkLight}; padding: 10px 12px; border-bottom: 2px solid ${TOKENS.ink}; }
        table.est-table td { padding: 10px 12px; border-bottom: 1px solid ${TOKENS.line}; vertical-align: middle; }
        .est-gauge-track { background: ${TOKENS.paperDark}; border-radius: 4px; height: 8px; overflow: hidden; width: 100%; }
        .est-gauge-fill { height: 100%; border-radius: 4px; }
        .est-modal-overlay { position: fixed; inset: 0; background: rgba(28,43,58,0.55); display: flex; align-items: center; justify-content: center; z-index: 50; padding: 16px; }
        .est-modal { background: #fff; border-radius: 12px; width: 100%; max-width: 440px; padding: 24px; max-height: 88vh; overflow-y: auto; }
        .est-stamp { font-family: 'Space Grotesk', sans-serif; font-weight: 700; font-size: 11px; letter-spacing: 0.05em; padding: 3px 10px; border-radius: 20px; display: inline-flex; align-items: center; gap: 4px; transform: rotate(-2deg); }
        .est-city { font-family: 'IBM Plex Mono', monospace; font-size: 12px; padding: 6px 12px; border-radius: 20px; cursor: pointer; border: 1px solid transparent; }
        .print-sheet { display: none; }
        @media print {
          .no-print { display: none !important; }
          .print-sheet { display: block !important; }
        }
      `}</style>

      {/* Header */}
      <div style={{ background: TOKENS.ink, padding: "22px 28px", borderRadius: "12px 12px 0 0" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ width: 44, height: 44, borderRadius: 8, background: "#ffffff12", display: "flex", alignItems: "center", justifyContent: "center", padding: 4 }}>
              <img src={LOGO_HEADER} alt="Logo" style={{ maxWidth: "100%", maxHeight: "100%", objectFit: "contain" }} />
            </div>
            <div>
              <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 20, color: TOKENS.paper, letterSpacing: "0.01em" }}>
                CONTROLE DE ESTOQUE
              </div>
              <div className="est-mono" style={{ fontSize: 11, color: "#B9C4CE" }}>gestão de produtos e movimentações por filial</div>
              {lastEdited && lastEdited.by && (
                <div className="est-mono" style={{ fontSize: 10, color: "#8996A3", marginTop: 2 }}>
                  Última atualização: {lastEdited.by} · {fmtDateTime(lastEdited.at)}
                </div>
              )}
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div className="est-mono" style={{ fontSize: 11, color: "#B9C4CE", background: "#ffffff14", padding: "6px 12px", borderRadius: 6 }}>
              {new Date().toLocaleDateString("pt-BR", { day: "2-digit", month: "long", year: "numeric" })}
            </div>
            <button
              type="button"
              onClick={downloadBackup}
              title="Baixar uma cópia completa do estoque (produtos + movimentações)"
              className="est-mono"
              style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, color: "#B9C4CE", background: "#ffffff14", border: "none", borderRadius: 6, padding: "6px 10px", cursor: "pointer" }}
            >
              <Download size={12} /> Backup
            </button>
            <button
              type="button"
              onClick={() => setShowChangelog(true)}
              title="Novidades"
              className="est-mono"
              style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, color: "#B9C4CE", background: "#ffffff14", border: "none", borderRadius: 6, padding: "6px 10px", cursor: "pointer" }}
            >
              <Sparkles size={12} /> Novidades
            </button>
            <LogoutButton />
          </div>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 16, flexWrap: "wrap" }}>
          <MapPin size={14} color="#B9C4CE" />
          {CITIES.map((c) => {
            const count = activeProducts.filter((p) => p.city === c).length;
            const active = c === city;
            return (
              <div
                key={c}
                className="est-city"
                onClick={() => setCity(c)}
                style={{
                  background: active ? TOKENS.amber : "#ffffff14",
                  color: active ? TOKENS.ink : "#D8DFE5",
                  fontWeight: active ? 600 : 400,
                }}
              >
                {c}{count === 0 ? " · sem dados" : ""}
              </div>
            );
          })}
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 6, padding: "16px 28px 0", background: TOKENS.paper, flexWrap: "wrap" }}>
        {[
          { key: "dashboard", label: "Painel", icon: LayoutGrid, color: TOKENS.teal },
          { key: "produtos", label: "Produtos", icon: Package, color: TOKENS.amber },
          { key: "movimentacoes", label: "Movimentações", icon: ClipboardList, color: TOKENS.rust },
          { key: "pedidos", label: "Pedidos", icon: ShoppingCart, color: TOKENS.inkLight },
          { key: "transferencias", label: "Transferência", icon: ArrowLeftRight, color: TOKENS.rustDark },
          { key: "relatorios", label: "Relatórios", icon: FileBarChart, color: TOKENS.purple },
        ].map((t) => {
          const Icon = t.icon;
          const active = tab === t.key;
          return (
            <div
              key={t.key}
              className="est-tab"
              onClick={() => setTab(t.key)}
              style={{
                display: "flex", alignItems: "center", gap: 6,
                padding: "9px 16px",
                borderRadius: "8px 8px 0 0",
                background: active ? "#fff" : t.color,
                color: active ? TOKENS.charcoal : "#fff",
                fontSize: 13,
                border: active ? `1px solid ${TOKENS.line}` : "none",
                borderBottom: active ? "1px solid #fff" : "none",
                marginBottom: -1,
                position: "relative",
                zIndex: active ? 2 : 1,
              }}
            >
              <Icon size={15} />
              {t.label}
            </div>
          );
        })}
      </div>

      <div style={{ background: "#fff", border: `1px solid ${TOKENS.line}`, borderTop: "none", borderRadius: "0 0 12px 12px", padding: 24, minHeight: 480 }}>
        {tab === "pedidos" ? (
          <PedidosTab
            products={activeProducts}
            city={city}
            onSave={updateOrderQuantities}
            onRequestPrint={setPrintTarget}
            onChangeSource={updateProductOrderSource}
            onResetSource={resetOrderSourceToMatriz}
          />
        ) : tab === "transferencias" ? (
          <TransferenciasTab products={activeProducts} movements={movements} onTransfer={transferStock} />
        ) : cityProducts.length === 0 ? (
          <EmptyCity city={city} onAdd={() => setProductModal("new")} />
        ) : (
          <>
            {tab === "dashboard" && (
              <Dashboard stats={stats} byCategory={byCategory} movementSeries={movementSeries} />
            )}

            {tab === "produtos" && (
              <ProdutosTab
                products={filteredProducts}
                allProducts={activeProducts}
                search={search}
                setSearch={setSearch}
                catFilter={catFilter}
                setCatFilter={setCatFilter}
                onNew={() => setProductModal("new")}
                onEdit={(p) => setProductModal(p)}
                onDelete={(p) => setConfirmDelete(p)}
                onConvert={(p) => setConvertModal(p)}
                trashCount={products.filter((p) => p.deleted).length}
                onOpenTrash={() => setShowTrash(true)}
              />
            )}

            {tab === "movimentacoes" && (
              <MovimentacoesTab
                products={cityProductsForHistory}
                movements={cityMovements}
                onEntrada={() => setMoveModal({ type: "entrada" })}
                onSaida={() => setMoveModal({ type: "saida" })}
                onImportar={() => setImportModal(true)}
                onEditMovement={(m) => setMoveEditModal(m)}
                onDeleteMovement={(m) => setConfirmDeleteMovement(m)}
              />
            )}

            {tab === "relatorios" && (
              <RelatoriosTab products={cityProducts} movements={cityMovements} stats={stats} />
            )}
          </>
        )}
      </div>

      {productModal && (
        <ProductModal
          product={productModal === "new" ? null : productModal}
          defaultCity={city}
          allProducts={activeProducts}
          onSave={saveProduct}
          onClose={() => setProductModal(null)}
        />
      )}

      {moveModal && (
        <MovementModal
          type={moveModal.type}
          products={cityProducts}
          onSave={addMovement}
          onClose={() => setMoveModal(null)}
        />
      )}

      {moveEditModal && (
        <MovementEditModal
          movement={moveEditModal}
          linkedMovement={
            moveEditModal.transferId
              ? movements.find((m) => m.transferId === moveEditModal.transferId && m.id !== moveEditModal.id)
              : null
          }
          products={activeProducts}
          onSave={(updates) => editMovement(moveEditModal, updates)}
          onDelete={() => { setConfirmDeleteMovement(moveEditModal); setMoveEditModal(null); }}
          onClose={() => setMoveEditModal(null)}
        />
      )}

      {convertModal && (
        <ConvertUnitModal
          product={convertModal}
          allProducts={activeProducts}
          onConvert={convertProductUnit}
          onClose={() => setConvertModal(null)}
        />
      )}

      {confirmDeleteMovement && (
        <div className="est-modal-overlay" onClick={() => setConfirmDeleteMovement(null)}>
          <div className="est-modal" onClick={(e) => e.stopPropagation()}>
            <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16, marginBottom: 8 }}>
              Apagar movimentação?
            </div>
            <p style={{ fontSize: 13, color: TOKENS.inkLight, marginBottom: 20 }}>
              {confirmDeleteMovement.transferId
                ? "Essa movimentação faz parte de uma transferência — os dois lados (origem e destino) serão apagados e o estoque de ambas as filiais volta ao que era antes."
                : "O estoque do produto será ajustado de volta, desfazendo o efeito dessa movimentação. Essa ação não pode ser desfeita."}
            </p>
            <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
              <button className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={() => setConfirmDeleteMovement(null)}>Cancelar</button>
              <button className="est-btn" style={{ background: TOKENS.rust, color: "#fff" }} onClick={() => deleteMovement(confirmDeleteMovement)}>Apagar</button>
            </div>
          </div>
        </div>
      )}

      {importModal && (
        <ImportModal
          products={cityProducts}
          city={city}
          onImport={importMovements}
          onClose={() => setImportModal(false)}
        />
      )}

      {confirmDelete && (
        <div className="est-modal-overlay" onClick={() => setConfirmDelete(null)}>
          <div className="est-modal" onClick={(e) => e.stopPropagation()}>
            <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16, marginBottom: 8 }}>
              Remover produto?
            </div>
            <p style={{ fontSize: 13, color: TOKENS.inkLight, marginBottom: 20 }}>
              "{confirmDelete.name}" some das telas de uso normal, mas o histórico de movimentações é mantido e dá pra restaurar depois pela Lixeira (aba Produtos).
            </p>
            <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
              <button className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={() => setConfirmDelete(null)}>Cancelar</button>
              <button className="est-btn" style={{ background: TOKENS.rust, color: "#fff" }} onClick={() => deleteProduct(confirmDelete.id)}>Remover</button>
            </div>
          </div>
        </div>
      )}

      {showChangelog && <ChangelogModal onClose={() => setShowChangelog(false)} />}

      {showTrash && (
        <TrashModal
          products={products.filter((p) => p.deleted)}
          onRestore={restoreProduct}
          onClose={() => setShowTrash(false)}
        />
      )}
    </div>

    <PrintSheet products={activeProducts} target={printTarget} />
    </>
  );
}

function PrintSheet({ products, target }) {
  if (!target) return null;
  const targetCity = target.city;
  const source = target.source || "matriz";
  const cities = targetCity === "all" ? CITIES : [targetCity];
  const dateStr = new Date().toLocaleDateString("pt-BR", { day: "2-digit", month: "long", year: "numeric" });
  return (
    <div className="print-sheet" style={{ fontFamily: "'Inter', sans-serif", color: "#1a1a1a", padding: "24px" }}>
      <style>{`
        @media print {
          @page { margin: 16mm; }
          body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
        }
        .ps-table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 8px; }
        .ps-table th { text-align: left; font-size: 10px; letter-spacing: 0.04em; text-transform: uppercase; color: #555; padding: 6px 8px; border-bottom: 1.5px solid #1a1a1a; }
        .ps-table td { padding: 6px 8px; border-bottom: 0.5px solid #ccc; }
        .ps-table thead { display: table-header-group; }
        .ps-table tr { break-inside: avoid; }
        .ps-city-heading { break-after: avoid; break-inside: avoid; }
        .ps-category-heading { break-after: avoid; break-inside: avoid; }
      `}</style>

      <div style={{ display: "flex", alignItems: "center", gap: 16, borderBottom: "2px solid #1a1a1a", paddingBottom: 16, marginBottom: 20 }}>
        <img src={LOGO_PRINT} alt="Logo" style={{ height: 56, objectFit: "contain" }} />
        <div>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 18 }}>
            {source === "local" ? "Compra local" : "Pedido de compra"}
          </div>
          <div style={{ fontSize: 12, color: "#555" }}>
            {targetCity === "all" ? "Todas as filiais" : targetCity} · gerado em {dateStr}
            {source === "local" ? " · itens de compra local (não enviar à matriz)" : ""}
          </div>
        </div>
      </div>

      {cities.map((c) => {
        const items = products.filter((p) => p.city === c && (Number(p.orderQty) || 0) > 0 && (p.orderSource || "matriz") === source);
        const total = items.reduce((s, p) => s + (Number(p.orderQty) || 0), 0);
        // Agrupa por setor (na ordem fixa de CATEGORIES) e ordena por nome
        // dentro de cada setor — facilita separar os itens fisicamente.
        const groups = CATEGORIES.map((cat) => ({
          category: cat,
          items: items.filter((p) => p.category === cat).sort((a, b) => a.name.localeCompare(b.name, "pt-BR")),
        })).filter((g) => g.items.length > 0);
        const otherItems = items
          .filter((p) => !CATEGORIES.includes(p.category))
          .sort((a, b) => a.name.localeCompare(b.name, "pt-BR"));
        if (otherItems.length > 0) groups.push({ category: "Outros", items: otherItems });

        return (
          <div key={c} style={{ marginBottom: 24 }}>
            <div className="ps-city-heading" style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 14, marginBottom: 6 }}>{c}</div>
            {items.length === 0 ? (
              <p style={{ fontSize: 12, color: "#777", marginBottom: 8 }}>Nenhum item com quantidade a pedir definida para esta filial.</p>
            ) : (
              groups.map((g) => (
                <div key={g.category} style={{ marginBottom: 10 }}>
                  <div className="ps-category-heading" style={{ fontSize: 11, fontWeight: 700, color: "#555", textTransform: "uppercase", letterSpacing: "0.04em", margin: "8px 0 4px" }}>
                    {g.category}
                  </div>
                  <table className="ps-table">
                    <thead>
                      <tr><th>SKU</th><th>Produto</th><th style={{ textAlign: "right" }}>Qtd.</th><th>Un.</th><th>Equivalente</th></tr>
                    </thead>
                    <tbody>
                      {g.items.map((p) => (
                        <tr key={p.id}>
                          <td>{p.sku}</td>
                          <td>{p.name}</td>
                          <td style={{ textAlign: "right" }}>{p.orderPackageUnit ? p.orderPackageQty : p.orderQty}</td>
                          <td>{p.orderPackageUnit || p.unit}</td>
                          <td>{p.orderPackageUnit ? `${p.orderQty} ${p.unit}` : "—"}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              ))
            )}
            {items.length > 0 && (
              <div style={{ fontSize: 12, textAlign: "right", color: "#333" }}>
                {items.length} itens · {total} unidades no total
              </div>
            )}
          </div>
        );
      })}

      <div style={{ fontSize: 10, color: "#999", borderTop: "0.5px solid #ccc", paddingTop: 10, marginTop: 12 }}>
        Documento gerado automaticamente pelo sistema de controle de estoque.
      </div>
    </div>
  );
}

function suggestedQty(p) {
  return Math.max(0, p.minStock - p.quantity);
}

// Só entra no pedido que vai pra matriz o que tiver quantidade definida E
// estiver marcado como "Matriz" — itens marcados como "Local" são comprados
// por fora e não devem aparecer no pedido enviado pra Umuarama.
function buildOrderText(cityName, cityProducts, drafts) {
  const items = cityProducts.filter((p) => (Number(drafts[p.id]?.qty) || 0) > 0 && (p.orderSource || "matriz") === "matriz");
  const dateStr = new Date().toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });
  let text = `PEDIDO DE COMPRA - ${cityName.toUpperCase()}\nData: ${dateStr}\n\n`;
  if (items.length === 0) {
    text += "Nenhum item com quantidade a pedir definida.\n";
  } else {
    items.forEach((p) => {
      const d = drafts[p.id];
      if (d.unit && d.unit !== p.unit) {
        text += `- ${p.name} (${p.sku}): ${d.packageQty} ${d.unit} (${d.qty} ${p.unit})\n`;
      } else {
        text += `- ${p.name} (${p.sku}): ${d.qty} ${p.unit}\n`;
      }
    });
    const total = items.reduce((s, p) => s + (Number(drafts[p.id]?.qty) || 0), 0);
    text += `\nTotal de itens: ${items.length}\nTotal de unidades: ${total}\n`;
  }
  return text;
}

function downloadTextFile(filename, text) {
  const blob = new Blob([text], { type: "text/plain;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function PedidosTab({ products, city, onSave, onRequestPrint, onChangeSource, onResetSource }) {
  const [drafts, setDrafts] = useState(() =>
    Object.fromEntries(
      products.map((p) => [
        p.id,
        {
          qty: p.orderQty || 0,
          unit: p.orderPackageUnit || p.unit,
          packageQty: p.orderPackageUnit ? (p.orderPackageQty ?? 0) : (p.orderQty || 0),
          factor: p.orderUnitsPerPackage ?? "",
        },
      ])
    )
  );
  const [dirty, setDirty] = useState(false);
  const [copied, setCopied] = useState(false);
  const [sort, setSort] = useState({ key: null, dir: "asc" });
  const [sourceFilter, setSourceFilter] = useState("todos");

  // Recalcula a quantidade real (na unidade-base do produto, hoje sempre
  // UN) a partir do que foi digitado em "Tipo" + "Qtd." — se o tipo
  // escolhido for diferente da unidade-base, usa o fator de conversão.
  function updateDraft(p, patch) {
    setDrafts((d) => {
      const cur = d[p.id] || { qty: 0, unit: p.unit, packageQty: 0, factor: "" };
      const next = { ...cur, ...patch };
      const needsFactor = next.unit !== p.unit;
      next.qty = needsFactor
        ? Math.round(((Number(next.packageQty) || 0) * (Number(next.factor) || 0)) * 100) / 100
        : Number(next.packageQty) || 0;
      return { ...d, [p.id]: next };
    });
    setDirty(true);
  }

  function toggleSort(key) {
    setSort((s) => (s.key === key ? { key, dir: s.dir === "asc" ? "desc" : "asc" } : { key, dir: "asc" }));
  }

  // Lista completa da filial, sem o filtro de origem — usada nos totais e
  // nas ações de "Sugerir"/"Limpar"/copiar/baixar/gerar PDF, que devem valer
  // pra tudo independente do que está sendo exibido na tabela no momento.
  const cityProductsAll = products.filter((p) => p.city === city);

  const cityProductsBySource =
    sourceFilter === "todos"
      ? cityProductsAll
      : cityProductsAll.filter((p) => (p.orderSource || "matriz") === sourceFilter);

  const cityProducts = useMemo(() => {
    if (!sort.key) {
      return [...cityProductsBySource].sort((a, b) => {
        const aLow = a.quantity <= a.minStock ? 0 : 1;
        const bLow = b.quantity <= b.minStock ? 0 : 1;
        if (aLow !== bLow) return aLow - bLow;
        return a.name.localeCompare(b.name);
      });
    }
    const col = PEDIDOS_COLUMNS.find((c) => c.key === sort.key);
    const mult = sort.dir === "asc" ? 1 : -1;
    return [...cityProductsBySource].sort((a, b) => {
      const va = a[sort.key];
      const vb = b[sort.key];
      if (col.type === "number") return ((Number(va) || 0) - (Number(vb) || 0)) * mult;
      return String(va || "").localeCompare(String(vb || ""), "pt-BR") * mult;
    });
  }, [cityProductsBySource, sort]);

  const matrizCount = cityProductsAll.filter((p) => (p.orderSource || "matriz") === "matriz").length;
  const localCount = cityProductsAll.filter((p) => (p.orderSource || "matriz") === "local").length;
  const matrizTotal = cityProductsAll.reduce(
    (s, p) => ((p.orderSource || "matriz") === "matriz" ? s + (Number(drafts[p.id]?.qty) || 0) : s),
    0
  );
  const localTotal = cityProductsAll.reduce(
    (s, p) => ((p.orderSource || "matriz") === "local" ? s + (Number(drafts[p.id]?.qty) || 0) : s),
    0
  );

  function suggestCity() {
    setDrafts((d) => {
      const next = { ...d };
      cityProductsAll.forEach((p) => {
        const q = suggestedQty(p);
        next[p.id] = { qty: q, unit: p.unit, packageQty: q, factor: "" };
      });
      return next;
    });
    setDirty(true);
  }

  function clearCity() {
    setDrafts((d) => {
      const next = { ...d };
      cityProductsAll.forEach((p) => { next[p.id] = { qty: 0, unit: p.unit, packageQty: 0, factor: "" }; });
      return next;
    });
    setDirty(true);
  }

  function saveAll() {
    onSave(drafts);
    setDirty(false);
  }

  async function copyOrder() {
    const text = buildOrderText(city, cityProductsAll, drafts);
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    } catch (e) {
      console.error("Falha ao copiar", e);
    }
  }

  function downloadOrder() {
    const text = buildOrderText(city, cityProductsAll, drafts);
    const safeName = city.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
    downloadTextFile(`pedido-${safeName}-${new Date().toISOString().slice(0, 10)}.txt`, text);
  }

  function generatePdf(source) {
    onSave(drafts);
    setDirty(false);
    onRequestPrint({ city, source });
  }

  function resetToMatriz() {
    onResetSource(city);
  }

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 10, marginBottom: 20 }}>
        <div>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16 }}>Pedido de compra — {city}</div>
          <p style={{ fontSize: 12, color: TOKENS.inkLight, margin: "4px 0 0" }}>
            Defina quanto pedir de cada item e marque se vai pra <strong>Matriz</strong> ou se é <strong>compra local</strong>. Só os itens marcados "Matriz" entram no pedido enviado pra Umuarama.
          </p>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
          <span className="est-mono" style={{ fontSize: 12, color: TOKENS.inkLight }}>
            Matriz: <strong style={{ color: TOKENS.charcoal }}>{matrizTotal}</strong> un. · Local: <strong style={{ color: TOKENS.charcoal }}>{localTotal}</strong> un.
          </span>
          <button className="est-btn" style={{ background: dirty ? TOKENS.ink : TOKENS.paperDark, color: dirty ? "#fff" : TOKENS.inkLight }} onClick={saveAll} disabled={!dirty}>
            Salvar pedido
          </button>
        </div>
      </div>

      <div className="est-card" style={{ padding: 16 }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 8, marginBottom: 12 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <MapPin size={14} color={TOKENS.inkLight} />
            <span style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 14 }}>{city}</span>
            <div style={{ display: "flex", gap: 4 }}>
              {[
                { key: "todos", label: `Todos (${cityProductsAll.length})` },
                { key: "matriz", label: `Matriz (${matrizCount})` },
                { key: "local", label: `Local (${localCount})` },
              ].map((f) => (
                <button
                  key={f.key}
                  type="button"
                  onClick={() => setSourceFilter(f.key)}
                  className="est-mono"
                  style={{
                    fontSize: 11, padding: "4px 10px", borderRadius: 20, cursor: "pointer",
                    border: `1px solid ${TOKENS.line}`,
                    background: sourceFilter === f.key ? TOKENS.ink : "#fff",
                    color: sourceFilter === f.key ? "#fff" : TOKENS.inkLight,
                  }}
                >
                  {f.label}
                </button>
              ))}
            </div>
          </div>
          {cityProductsAll.length > 0 && (
            <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
              <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal, padding: "6px 10px", fontSize: 12 }} onClick={suggestCity}>
                <Wand2 size={12} /> Sugerir
              </button>
              <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal, padding: "6px 10px", fontSize: 12 }} onClick={clearCity}>
                Limpar
              </button>
              {localCount > 0 && (
                <button
                  type="button"
                  className="est-btn"
                  style={{ background: TOKENS.paperDark, color: TOKENS.charcoal, padding: "6px 10px", fontSize: 12 }}
                  onClick={resetToMatriz}
                  title="Marca todos os itens dessa filial de volta como Matriz"
                >
                  <RotateCcw size={12} /> Redefinir p/ Matriz
                </button>
              )}
              <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal, padding: "6px 10px", fontSize: 12 }} onClick={copyOrder}>
                {copied ? <Check size={12} /> : <Copy size={12} />} {copied ? "Copiado" : "Copiar"}
              </button>
              <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal, padding: "6px 10px", fontSize: 12 }} onClick={downloadOrder}>
                <Download size={12} /> .txt
              </button>
              <button type="button" className="est-btn" style={{ background: TOKENS.ink, color: "#fff", padding: "6px 10px", fontSize: 12 }} onClick={() => generatePdf("matriz")}>
                <FileText size={12} /> PDF (Matriz)
              </button>
              {localCount > 0 && (
                <button type="button" className="est-btn" style={{ background: TOKENS.amber, color: TOKENS.ink, padding: "6px 10px", fontSize: 12 }} onClick={() => generatePdf("local")}>
                  <FileText size={12} /> PDF (Local)
                </button>
              )}
            </div>
          )}
        </div>

        {cityProductsAll.length === 0 ? (
          <p style={{ fontSize: 12, color: TOKENS.inkLight }}>Sem produtos cadastrados nesta filial ainda.</p>
        ) : cityProducts.length === 0 ? (
          <p style={{ fontSize: 12, color: TOKENS.inkLight }}>Nenhum item nesse filtro.</p>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table className="est-table">
              <thead>
                <tr>
                  {PEDIDOS_COLUMNS.map((col) => {
                    const active = sort.key === col.key;
                    const Icon = active ? (sort.dir === "asc" ? ChevronUp : ChevronDown) : ChevronsUpDown;
                    return (
                      <th
                        key={col.key}
                        onClick={() => toggleSort(col.key)}
                        style={{ cursor: "pointer", userSelect: "none", whiteSpace: "nowrap" }}
                        title="Clique para ordenar"
                      >
                        <span style={{ display: "inline-flex", alignItems: "center", gap: 3 }}>
                          {col.label}
                          <Icon size={12} color={active ? TOKENS.ink : TOKENS.line} />
                        </span>
                      </th>
                    );
                  })}
                  <th>Qtd. a pedir</th>
                  <th>Origem</th>
                </tr>
              </thead>
              <tbody>
                {cityProducts.map((p) => {
                  const low = p.quantity <= p.minStock;
                  const d = drafts[p.id] || { qty: 0, unit: p.unit, packageQty: 0, factor: "" };
                  return (
                    <tr key={p.id}>
                      <td style={{ fontWeight: 500 }}>{p.name}</td>
                      <td style={{ color: TOKENS.inkLight }}>{p.category}</td>
                      <td className="est-mono" style={{ color: low ? TOKENS.rustDark : TOKENS.charcoal }}>{p.quantity} {p.unit}</td>
                      <td className="est-mono" style={{ color: TOKENS.inkLight }}>{p.minStock}</td>
                      <td style={{ minWidth: 190 }}>
                        <PackageQtyInput
                          baseUnit={p.unit}
                          quantity={d.packageQty}
                          onQuantityChange={(v) => updateDraft(p, { packageQty: v })}
                          unitType={d.unit}
                          onUnitTypeChange={(v) => updateDraft(p, { unit: v })}
                          factor={d.factor}
                          onFactorChange={(v) => updateDraft(p, { factor: v })}
                          label="Qtd. a pedir"
                        />
                      </td>
                      <td>
                        <OrderSourceToggle value={p.orderSource} onChange={(v) => onChangeSource(p.id, v)} />
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

function TransferenciasTab({ products, movements, onTransfer }) {
  const [fromCity, setFromCity] = useState(CITIES[0]);
  const [toCity, setToCity] = useState(CITIES.find((c) => c !== CITIES[0]) || CITIES[0]);
  const [productId, setProductId] = useState("");
  const [quantity, setQuantity] = useState("");
  const [unitType, setUnitType] = useState("UN");
  const [factor, setFactor] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const fromProducts = products
    .filter((p) => p.city === fromCity)
    .sort((a, b) => a.name.localeCompare(b.name));
  const selectedProduct = fromProducts.find((p) => p.id === productId) || null;
  const toOptions = CITIES.filter((c) => c !== fromCity);
  const baseUnit = selectedProduct ? selectedProduct.unit : "UN";
  const needsFactor = unitType !== baseUnit;
  const totalQty = needsFactor
    ? Math.round(((Number(quantity) || 0) * (Number(factor) || 0)) * 100) / 100
    : Number(quantity) || 0;

  function handleFromCity(c) {
    setFromCity(c);
    setProductId("");
    setError("");
    setSuccess("");
    if (toCity === c) {
      setToCity(CITIES.find((x) => x !== c) || c);
    }
  }

  function handleToCity(c) {
    setToCity(c);
    setError("");
    setSuccess("");
  }

  function handleProductChange(id) {
    setProductId(id);
    const p = fromProducts.find((x) => x.id === id);
    setUnitType(p ? p.unit : "UN");
    setFactor("");
    setError("");
    setSuccess("");
  }

  function submit(e) {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (fromCity === toCity) {
      setError("Escolha duas filiais diferentes.");
      return;
    }
    if (!selectedProduct) {
      setError("Escolha um produto.");
      return;
    }
    if (!totalQty || totalQty <= 0) {
      setError("Informe uma quantidade válida.");
      return;
    }
    if (totalQty > selectedProduct.quantity) {
      setError(`Quantidade maior que o estoque disponível (${selectedProduct.quantity} ${selectedProduct.unit}).`);
      return;
    }

    onTransfer({
      fromCity,
      toCity,
      product: selectedProduct,
      quantity: totalQty,
      packageInfo: needsFactor
        ? { packageUnit: unitType, packageQty: Number(quantity), unitsPerPackage: Number(factor) }
        : undefined,
    });
    setSuccess(`${totalQty} ${selectedProduct.unit} de "${selectedProduct.name}" transferido(s) de ${fromCity} para ${toCity}.`);
    setProductId("");
    setQuantity("");
    setUnitType("UN");
    setFactor("");
  }

  const recentTransfers = movements
    .filter((m) => m.transferId && m.type === "saida")
    .slice(0, 15);

  return (
    <div>
      <div style={{ marginBottom: 20 }}>
        <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16 }}>Transferência entre filiais</div>
        <p style={{ fontSize: 12, color: TOKENS.inkLight, margin: "4px 0 0" }}>
          Escolha de onde e pra onde vai o material — a quantidade sai do estoque de origem e entra no de destino.
        </p>
      </div>

      <form onSubmit={submit} className="est-card" style={{ padding: 16, marginBottom: 20, display: "flex", flexDirection: "column", gap: 14 }}>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 12 }}>
          <Field label="De (origem)" style={{ flex: "1 1 160px" }}>
            <select className="est-input" style={{ width: "100%" }} value={fromCity} onChange={(e) => handleFromCity(e.target.value)}>
              {CITIES.map((c) => <option key={c}>{c}</option>)}
            </select>
          </Field>
          <div style={{ display: "flex", alignItems: "flex-end", paddingBottom: 8, color: TOKENS.inkLight }}>
            <ArrowLeftRight size={16} />
          </div>
          <Field label="Para (destino)" style={{ flex: "1 1 160px" }}>
            <select className="est-input" style={{ width: "100%" }} value={toCity} onChange={(e) => handleToCity(e.target.value)}>
              {toOptions.map((c) => <option key={c}>{c}</option>)}
            </select>
          </Field>
        </div>

        {fromProducts.length === 0 ? (
          <p style={{ fontSize: 12, color: TOKENS.inkLight }}>Sem produtos cadastrados em {fromCity}.</p>
        ) : (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 12 }}>
            <Field label="Material" style={{ flex: "2 1 260px" }}>
              <select
                className="est-input"
                style={{ width: "100%" }}
                value={productId}
                onChange={(e) => handleProductChange(e.target.value)}
              >
                <option value="">Selecione…</option>
                {fromProducts.map((p) => (
                  <option key={p.id} value={p.id}>
                    {p.name} — {p.quantity} {p.unit} em estoque
                  </option>
                ))}
              </select>
            </Field>
            {selectedProduct && (
              <div style={{ flex: "1 1 220px" }}>
                <PackageQtyInput
                  baseUnit={baseUnit}
                  quantity={quantity}
                  onQuantityChange={(v) => { setQuantity(v); setError(""); setSuccess(""); }}
                  unitType={unitType}
                  onUnitTypeChange={(v) => { setUnitType(v); setError(""); setSuccess(""); }}
                  factor={factor}
                  onFactorChange={(v) => { setFactor(v); setError(""); setSuccess(""); }}
                />
              </div>
            )}
          </div>
        )}

        {error && <div style={{ fontSize: 12, color: TOKENS.rustDark }}>{error}</div>}
        {success && <div style={{ fontSize: 12, color: TOKENS.tealDark }}>{success}</div>}

        <div>
          <button type="submit" className="est-btn" style={{ background: TOKENS.ink, color: "#fff" }} disabled={fromProducts.length === 0}>
            <ArrowLeftRight size={14} /> Transferir
          </button>
        </div>
      </form>

      <div className="est-card" style={{ padding: 16 }}>
        <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 14, marginBottom: 12 }}>
          Transferências recentes
        </div>
        {recentTransfers.length === 0 ? (
          <p style={{ fontSize: 12, color: TOKENS.inkLight }}>Nenhuma transferência registrada ainda.</p>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table className="est-table">
              <thead>
                <tr><th>Data</th><th>De</th><th>Para</th><th>Qtd.</th></tr>
              </thead>
              <tbody>
                {recentTransfers.map((m) => {
                  const product = products.find((p) => p.id === m.productId);
                  const toMovement = movements.find((x) => x.transferId === m.transferId && x.type === "entrada");
                  return (
                    <tr key={m.id}>
                      <td className="est-mono" style={{ color: TOKENS.inkLight }}>{fmtDate(m.date)}</td>
                      <td>{m.city}</td>
                      <td>{toMovement ? toMovement.city : "—"}</td>
                      <td className="est-mono">
                        {m.packageUnit ? `${m.packageQty} ${m.packageUnit} (${m.quantity} ${product ? product.unit : ""})` : `${m.quantity} ${product ? product.unit : ""}`}
                        {" "}· {product ? product.name : "produto removido"}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

