function StockGauge({ quantity, minStock }) {
  const ratio = minStock > 0 ? quantity / (minStock * 2) : quantity > 0 ? 1 : 0;
  const pct = Math.max(quantity > 0 ? 4 : 0, Math.min(100, ratio * 100));
  const color = quantity <= minStock ? TOKENS.rust : quantity <= minStock * 1.5 ? TOKENS.amber : TOKENS.teal;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
      <div className="est-gauge-track" style={{ width: 70 }}>
        <div className="est-gauge-fill" style={{ width: `${pct}%`, background: color }} />
      </div>
      <span className="est-mono" style={{ fontSize: 12, minWidth: 20, color: TOKENS.charcoal }}>{quantity}</span>
    </div>
  );
}

const PRODUTOS_COLUMNS = [
  { key: "sku", label: "SKU", type: "text" },
  { key: "name", label: "Produto", type: "text" },
  { key: "category", label: "Setor", type: "text" },
  { key: "unit", label: "Un.", type: "text" },
  { key: "quantity", label: "Estoque", type: "number" },
  { key: "minStock", label: "Mínimo", type: "number" },
  { key: "unitPrice", label: "Preço", type: "number" },
];

const PEDIDOS_COLUMNS = [
  { key: "name", label: "Produto", type: "text" },
  { key: "category", label: "Setor", type: "text" },
  { key: "quantity", label: "Estoque", type: "number" },
  { key: "minStock", label: "Mínimo", type: "number" },
];

function ProdutosTab({ products, allProducts, search, setSearch, catFilter, setCatFilter, onNew, onEdit, onDelete, onConvert, trashCount, onOpenTrash }) {
  const duplicateGroups = findDuplicateSkus(allProducts || products);
  const [sort, setSort] = useState({ key: null, dir: "asc" });

  function toggleSort(key) {
    setSort((s) => (s.key === key ? { key, dir: s.dir === "asc" ? "desc" : "asc" } : { key, dir: "asc" }));
  }

  const sortedProducts = useMemo(() => {
    if (!sort.key) return products;
    const col = PRODUTOS_COLUMNS.find((c) => c.key === sort.key);
    const mult = sort.dir === "asc" ? 1 : -1;
    return [...products].sort((a, b) => {
      const va = a[sort.key];
      const vb = b[sort.key];
      if (col.type === "number") return ((Number(va) || 0) - (Number(vb) || 0)) * mult;
      return String(va || "").localeCompare(String(vb || ""), "pt-BR") * mult;
    });
  }, [products, sort]);

  return (
    <div>
      {duplicateGroups.length > 0 && (
        <div style={{ display: "flex", gap: 10, alignItems: "flex-start", background: `${TOKENS.rust}14`, border: `1px solid ${TOKENS.rust}44`, borderRadius: 8, padding: "10px 14px", marginBottom: 16 }}>
          <AlertTriangle size={16} color={TOKENS.rustDark} style={{ flexShrink: 0, marginTop: 1 }} />
          <div style={{ fontSize: 12, color: TOKENS.rustDark }}>
            <strong>{duplicateGroups.length} SKU{duplicateGroups.length > 1 ? "s" : ""} duplicado{duplicateGroups.length > 1 ? "s" : ""}</strong> — o mesmo código está em produtos diferentes, o que pode confundir transferências e importações. Renomeie o SKU de um deles:
            <ul style={{ margin: "6px 0 0", paddingLeft: 18 }}>
              {duplicateGroups.map((group) => (
                <li key={normalizeSku(group[0].sku)}>
                  <span className="est-mono">{group[0].sku}</span>: {group.map((p) => `${p.name} (${p.city})`).join(", ")}
                </li>
              ))}
            </ul>
          </div>
        </div>
      )}

      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <div style={{ position: "relative" }}>
            <Search size={14} style={{ position: "absolute", left: 10, top: 10, color: TOKENS.inkLight }} />
            <input className="est-input" style={{ paddingLeft: 30, width: 200 }} placeholder="Buscar por nome ou SKU"
              value={search} onChange={(e) => setSearch(e.target.value)} />
          </div>
          <select className="est-input" value={catFilter} onChange={(e) => setCatFilter(e.target.value)}>
            <option>Todos</option>
            {CATEGORIES.map((c) => <option key={c}>{c}</option>)}
          </select>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {trashCount > 0 && (
            <button className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={onOpenTrash}>
              <Archive size={14} /> Lixeira ({trashCount})
            </button>
          )}
          <button className="est-btn" style={{ background: TOKENS.ink, color: "#fff" }} onClick={onNew}>
            <Plus size={14} /> Novo produto
          </button>
        </div>
      </div>

      <div style={{ overflowX: "auto" }}>
        <table className="est-table">
          <thead>
            <tr>
              {PRODUTOS_COLUMNS.map((col) => {
                const active = sort.key === col.key;
                const Icon = active ? (sort.dir === "asc" ? ChevronUp : ChevronDown) : ChevronsUpDown;
                return (
                  <th
                    key={col.key}
                    onClick={() => toggleSort(col.key)}
                    style={{ cursor: "pointer", userSelect: "none", whiteSpace: "nowrap" }}
                    title="Clique para ordenar"
                  >
                    <span style={{ display: "inline-flex", alignItems: "center", gap: 3 }}>
                      {col.label}
                      <Icon size={12} color={active ? TOKENS.ink : TOKENS.line} />
                    </span>
                  </th>
                );
              })}
              <th></th>
            </tr>
          </thead>
          <tbody>
            {sortedProducts.length === 0 && (
              <tr><td colSpan={8} style={{ textAlign: "center", padding: 24, color: TOKENS.inkLight }}>Nenhum produto encontrado.</td></tr>
            )}
            {sortedProducts.map((p) => {
              const st = CAT_STYLE[p.category] || { color: TOKENS.ink, dark: TOKENS.ink };
              return (
                <tr key={p.id}>
                  <td className="est-mono" style={{ color: TOKENS.inkLight }}>{p.sku}</td>
                  <td style={{ fontWeight: 500 }}>{p.name}</td>
                  <td>
                    <span className="est-stamp" style={{ background: `${st.color}18`, color: st.dark, transform: "none" }}>{p.category}</span>
                  </td>
                  <td className="est-mono" style={{ color: TOKENS.inkLight }}>{p.unit}</td>
                  <td><StockGauge quantity={p.quantity} minStock={p.minStock} /></td>
                  <td className="est-mono" style={{ color: TOKENS.inkLight }}>{p.minStock}</td>
                  <td className="est-mono">{p.unitPrice > 0 ? fmtBRL(p.unitPrice) : "—"}</td>
                  <td>
                    <div style={{ display: "flex", gap: 6 }}>
                      {p.unit !== "UN" && (
                        <button onClick={() => onConvert(p)} title="Converter para UN" style={{ background: "none", border: "none", cursor: "pointer", color: TOKENS.purple }}><Divide size={14} /></button>
                      )}
                      <button onClick={() => onEdit(p)} style={{ background: "none", border: "none", cursor: "pointer", color: TOKENS.teal }}><Edit2 size={14} /></button>
                      <button onClick={() => onDelete(p)} style={{ background: "none", border: "none", cursor: "pointer", color: TOKENS.rust }}><Trash2 size={14} /></button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function MovimentacoesTab({ products, movements, onEntrada, onSaida, onImportar, onEditMovement, onDeleteMovement }) {
  const productMap = Object.fromEntries(products.map((p) => [p.id, p]));
  const sorted = [...movements].sort((a, b) => new Date(b.date) - new Date(a.date)).slice(0, 60);
  return (
    <div>
      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
        <button className="est-btn" style={{ background: TOKENS.teal, color: "#fff" }} onClick={onEntrada}>
          <ArrowUpCircle size={14} /> Registrar entrada
        </button>
        <button className="est-btn" style={{ background: TOKENS.rust, color: "#fff" }} onClick={onSaida}>
          <ArrowDownCircle size={14} /> Registrar saída
        </button>
        <button className="est-btn" style={{ background: TOKENS.purple, color: "#fff" }} onClick={onImportar}>
          <Upload size={14} /> Importar planilha
        </button>
      </div>
      <div style={{ overflowX: "auto" }}>
        <table className="est-table">
          <thead>
            <tr><th>Data</th><th>Tipo</th><th>Produto</th><th>Quantidade</th><th>Observação</th><th>Por</th><th></th></tr>
          </thead>
          <tbody>
            {sorted.length === 0 && (
              <tr><td colSpan={7} style={{ textAlign: "center", padding: 24, color: TOKENS.inkLight }}>Nenhuma movimentação registrada nesta filial ainda.</td></tr>
            )}
            {sorted.map((m) => {
              const p = productMap[m.productId];
              const isIn = m.type === "entrada";
              return (
                <tr key={m.id}>
                  <td className="est-mono" style={{ color: TOKENS.inkLight }}>{fmtDate(m.date)}</td>
                  <td>
                    <span className="est-stamp" style={{
                      background: isIn ? `${TOKENS.teal}18` : `${TOKENS.rust}18`,
                      color: isIn ? TOKENS.tealDark : TOKENS.rustDark,
                    }}>
                      {isIn ? "ENTRADA ▲" : "SAÍDA ▼"}
                    </span>
                    {isIn && m.source && (
                      <div style={{ fontSize: 10, color: TOKENS.inkLight, marginTop: 4 }}>
                        {m.source === "matriz" ? "via Matriz" : "compra local"}
                      </div>
                    )}
                  </td>
                  <td>{p ? p.name : "Produto removido"}</td>
                  <td className="est-mono">
                    {m.packageUnit ? (
                      <>
                        {m.packageQty} {m.packageUnit}{" "}
                        <span style={{ color: TOKENS.inkLight }}>({m.quantity} {p ? p.unit : ""})</span>
                      </>
                    ) : (
                      <>{m.quantity} {p ? p.unit : ""}</>
                    )}
                  </td>
                  <td style={{ color: TOKENS.inkLight, fontSize: 12 }}>{m.note || "—"}</td>
                  <td style={{ color: TOKENS.inkLight, fontSize: 12 }}>
                    {m.createdBy || "—"}
                    {m.editedBy && <div style={{ fontSize: 10 }}>editado por {m.editedBy}</div>}
                  </td>
                  <td>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => onEditMovement(m)} style={{ background: "none", border: "none", cursor: "pointer", color: TOKENS.teal }}><Edit2 size={14} /></button>
                      <button onClick={() => onDeleteMovement(m)} style={{ background: "none", border: "none", cursor: "pointer", color: TOKENS.rust }}><Trash2 size={14} /></button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function RelatoriosTab({ products, movements, stats }) {
  const zerados = products.filter((p) => p.quantity === 0);
  const lowStock = products.filter((p) => p.quantity > 0 && p.quantity <= p.minStock);
  const maisEstocados = [...products].sort((a, b) => b.quantity - a.quantity).slice(0, 8);
  const now = new Date();
  const monthMoves = movements.filter((m) => {
    const d = new Date(m.date);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  });
  const entradasMes = monthMoves.filter((m) => m.type === "entrada").reduce((s, m) => s + m.quantity, 0);
  const saidasMes = monthMoves.filter((m) => m.type === "saida").reduce((s, m) => s + m.quantity, 0);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))", gap: 12 }}>
        <MetricCard label="Entradas no mês" value={entradasMes} icon={ArrowUpCircle} accent={TOKENS.teal} />
        <MetricCard label="Saídas no mês" value={saidasMes} icon={ArrowDownCircle} accent={TOKENS.rust} />
        <MetricCard label="Itens zerados" value={zerados.length} icon={AlertTriangle} accent={TOKENS.rust} />
      </div>

      <div className="est-card" style={{ padding: 16 }}>
        <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 13, marginBottom: 12, display: "flex", alignItems: "center", gap: 6, color: TOKENS.rustDark }}>
          <AlertTriangle size={15} /> Itens zerados ({zerados.length})
        </div>
        {zerados.length === 0 ? (
          <p style={{ fontSize: 13, color: TOKENS.inkLight }}>Nenhum item zerado no momento.</p>
        ) : (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
            {zerados.map((p) => (
              <span key={p.id} className="est-stamp" style={{ background: `${TOKENS.rust}18`, color: TOKENS.rustDark, transform: "none" }}>{p.name}</span>
            ))}
          </div>
        )}
      </div>

      <div className="est-card" style={{ padding: 16 }}>
        <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 13, marginBottom: 12, display: "flex", alignItems: "center", gap: 6, color: TOKENS.amberDark }}>
          <AlertTriangle size={15} /> Abaixo do estoque mínimo ({lowStock.length})
        </div>
        {lowStock.length === 0 ? (
          <p style={{ fontSize: 13, color: TOKENS.inkLight }}>Nenhum item abaixo do mínimo além dos zerados.</p>
        ) : (
          <table className="est-table">
            <thead><tr><th>Produto</th><th>Setor</th><th>Estoque atual</th><th>Mínimo</th></tr></thead>
            <tbody>
              {lowStock.map((p) => (
                <tr key={p.id}>
                  <td>{p.name}</td>
                  <td style={{ color: TOKENS.inkLight }}>{p.category}</td>
                  <td className="est-mono">{p.quantity}</td>
                  <td className="est-mono">{p.minStock}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <div className="est-card" style={{ padding: 16 }}>
        <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 13, marginBottom: 12 }}>
          Itens com maior quantidade em estoque
        </div>
        <table className="est-table">
          <thead><tr><th>Produto</th><th>Setor</th><th>Qtd.</th></tr></thead>
          <tbody>
            {maisEstocados.map((p) => (
              <tr key={p.id}>
                <td>{p.name}</td>
                <td style={{ color: TOKENS.inkLight }}>{p.category}</td>
                <td className="est-mono">{p.quantity} {p.unit}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function ProductModal({ product, defaultCity, allProducts, onSave, onClose }) {
  const isEdit = !!product;
  const [form, setForm] = useState(product || {
    name: "", sku: "", category: CATEGORIES[0], quantity: 0, minStock: 5, unitPrice: 0, unit: "UN", city: defaultCity,
  });
  const [skuError, setSkuError] = useState("");
  // Guarda o último SKU sugerido automaticamente, pra saber se pode trocar a
  // sugestão quando o setor muda (só troca se o usuário não tiver digitado
  // um SKU próprio por cima).
  const [lastSuggested, setLastSuggested] = useState(() =>
    isEdit ? null : suggestSku(CATEGORIES[0], allProducts || [])
  );

  useEffect(() => {
    if (isEdit) return;
    if (!form.sku.trim() || form.sku === lastSuggested) {
      const next = suggestSku(form.category, allProducts || []);
      setLastSuggested(next);
      setForm((f) => ({ ...f, sku: next }));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [form.category]);

  function update(field, value) {
    setForm((f) => ({ ...f, [field]: value }));
    if (field === "sku") setSkuError("");
  }

  function submit(e) {
    e.preventDefault();
    if (!form.name.trim() || !form.sku.trim()) return;

    // Reaproveitar o mesmo SKU em filiais diferentes é normal (é assim que o
    // catálogo replicado identifica "o mesmo item" em cada cidade). Só é
    // bloqueado quando é uma colisão de verdade: outro produto com nome
    // diferente usando esse SKU, ou outro produto na MESMA filial.
    const duplicate = (allProducts || []).find(
      (p) =>
        p.id !== form.id &&
        normalizeSku(p.sku) === normalizeSku(form.sku) &&
        (p.name.trim().toLowerCase() !== form.name.trim().toLowerCase() || p.city === form.city)
    );
    if (duplicate) {
      setSkuError(`Esse SKU já está em uso por "${duplicate.name}" (${duplicate.city}). Escolha outro.`);
      return;
    }

    onSave({ ...form, quantity: Number(form.quantity), minStock: Number(form.minStock), unitPrice: Number(form.unitPrice) });
  }
  return (
    <div className="est-modal-overlay" onClick={onClose}>
      <form className="est-modal" onClick={(e) => e.stopPropagation()} onSubmit={submit}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16 }}>
            {isEdit ? "Editar produto" : "Novo produto"}
          </div>
          <button type="button" onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={18} /></button>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <Field label="Nome do produto">
            <input className="est-input" style={{ width: "100%" }} value={form.name} onChange={(e) => update("name", e.target.value)} required />
          </Field>
          <div style={{ display: "flex", gap: 10 }}>
            <Field label="SKU" style={{ flex: 1 }}>
              <input className="est-input" style={{ width: "100%" }} value={form.sku} onChange={(e) => update("sku", e.target.value)} required />
              {skuError && <div style={{ fontSize: 11, color: TOKENS.rustDark, marginTop: 4 }}>{skuError}</div>}
            </Field>
            <Field label="Setor" style={{ flex: 1 }}>
              <select className="est-input" style={{ width: "100%" }} value={form.category} onChange={(e) => update("category", e.target.value)}>
                {CATEGORIES.map((c) => <option key={c}>{c}</option>)}
              </select>
            </Field>
          </div>
          <Field label="Filial">
            <select className="est-input" style={{ width: "100%" }} value={form.city} onChange={(e) => update("city", e.target.value)}>
              {CITIES.map((c) => <option key={c}>{c}</option>)}
            </select>
          </Field>
          <div style={{ display: "flex", gap: 10 }}>
            <Field label="Quantidade" style={{ flex: 1 }}>
              <input className="est-input" style={{ width: "100%" }} type="number" min="0" value={form.quantity} onChange={(e) => update("quantity", e.target.value)} />
            </Field>
            <Field label="Estoque mínimo" style={{ flex: 1 }}>
              <input className="est-input" style={{ width: "100%" }} type="number" min="0" value={form.minStock} onChange={(e) => update("minStock", e.target.value)} />
            </Field>
            <Field label="Unidade de medida" style={{ flex: 1 }}>
              <select className="est-input" style={{ width: "100%" }} value={form.unit} onChange={(e) => update("unit", e.target.value)}>
                {UNITS.map((u) => <option key={u}>{u}</option>)}
              </select>
            </Field>
          </div>
          <Field label="Preço unitário (R$) — opcional">
            <input className="est-input" style={{ width: "100%" }} type="number" min="0" step="0.01" value={form.unitPrice} onChange={(e) => update("unitPrice", e.target.value)} />
          </Field>
        </div>

        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 20 }}>
          <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={onClose}>Cancelar</button>
          <button type="submit" className="est-btn" style={{ background: TOKENS.ink, color: "#fff" }}>{isEdit ? "Salvar alterações" : "Adicionar produto"}</button>
        </div>
      </form>
    </div>
  );
}

function ConvertUnitModal({ product, allProducts, onConvert, onClose }) {
  const [factor, setFactor] = useState("");
  const relatedProducts = allProducts.filter(
    (p) => p.name.trim().toLowerCase() === product.name.trim().toLowerCase() && p.unit !== "UN"
  );
  const f = Number(factor) || 0;

  function submit(e) {
    e.preventDefault();
    if (f <= 0) return;
    onConvert(product.name, f);
  }

  return (
    <div className="est-modal-overlay" onClick={onClose}>
      <form className="est-modal" onClick={(e) => e.stopPropagation()} onSubmit={submit}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16 }}>
            Converter "{product.name}" para UN
          </div>
          <button type="button" onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={18} /></button>
        </div>
        <p style={{ fontSize: 12, color: TOKENS.inkLight, marginBottom: 14 }}>
          Isso converte esse item para UN em <strong>todas as filiais</strong> de uma vez (estoque, mínimo, preço unitário e qtd. a pedir são recalculados). O SKU não muda.
        </p>
        <Field label={`Quantas UN tem em 1 ${product.unit}?`}>
          <input className="est-input" style={{ width: "100%" }} type="number" min="0" step="0.01" autoFocus value={factor} onChange={(e) => setFactor(e.target.value)} placeholder="ex: 15" required />
        </Field>
        {f > 0 && (
          <div style={{ marginTop: 14, display: "flex", flexDirection: "column", gap: 6 }}>
            <div style={{ fontSize: 11, color: TOKENS.inkLight, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.04em" }}>Prévia</div>
            {relatedProducts.map((p) => (
              <div key={p.id} className="est-mono" style={{ fontSize: 12, display: "flex", justifyContent: "space-between", color: TOKENS.charcoal }}>
                <span>{p.city}</span>
                <span>{p.quantity} {p.unit} → {Math.round(p.quantity * f)} UN</span>
              </div>
            ))}
          </div>
        )}
        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 20 }}>
          <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={onClose}>Cancelar</button>
          <button type="submit" className="est-btn" style={{ background: TOKENS.ink, color: "#fff" }} disabled={f <= 0}>Converter</button>
        </div>
      </form>
    </div>
  );
}

function MovementModal({ type, products, onSave, onClose }) {
  const [productId, setProductId] = useState(products[0]?.id || "");
  const [quantity, setQuantity] = useState(1);
  const [unitType, setUnitType] = useState(products[0]?.unit || "UN");
  const [factor, setFactor] = useState("");
  const [source, setSource] = useState("");
  const [note, setNote] = useState("");
  const isIn = type === "entrada";
  const selected = products.find((p) => p.id === productId);

  function handleProductChange(id) {
    setProductId(id);
    const p = products.find((x) => x.id === id);
    setUnitType(p ? p.unit : "UN");
    setFactor("");
  }

  const baseUnit = selected ? selected.unit : "UN";
  const needsFactor = unitType !== baseUnit;
  const totalQty = needsFactor
    ? Math.round(((Number(quantity) || 0) * (Number(factor) || 0)) * 100) / 100
    : Number(quantity) || 0;

  function submit(e) {
    e.preventDefault();
    if (!productId || totalQty <= 0) return;
    if (isIn && !source) return;
    onSave({
      productId,
      type,
      quantity: totalQty,
      note,
      ...(needsFactor
        ? { packageUnit: unitType, packageQty: Number(quantity), unitsPerPackage: Number(factor) }
        : {}),
      ...(isIn ? { source } : {}),
    });
  }

  return (
    <div className="est-modal-overlay" onClick={onClose}>
      <form className="est-modal" onClick={(e) => e.stopPropagation()} onSubmit={submit}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16, color: isIn ? TOKENS.tealDark : TOKENS.rustDark }}>
            {isIn ? "Registrar entrada" : "Registrar saída"}
          </div>
          <button type="button" onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={18} /></button>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <Field label="Produto">
            <select className="est-input" style={{ width: "100%" }} value={productId} onChange={(e) => handleProductChange(e.target.value)}>
              {products.map((p) => <option key={p.id} value={p.id}>{p.name} ({p.sku})</option>)}
            </select>
          </Field>
          <PackageQtyInput
            baseUnit={baseUnit}
            quantity={quantity}
            onQuantityChange={setQuantity}
            unitType={unitType}
            onUnitTypeChange={setUnitType}
            factor={factor}
            onFactorChange={setFactor}
          />
          {isIn && (
            <Field label="Origem da entrada">
              <select className="est-input" style={{ width: "100%" }} value={source} onChange={(e) => setSource(e.target.value)} required>
                <option value="" disabled>Selecione…</option>
                <option value="local">Comprado localmente</option>
                <option value="matriz">Veio da matriz (Umuarama)</option>
              </select>
            </Field>
          )}
          {selected && !isIn && totalQty > selected.quantity && (
            <div style={{ fontSize: 12, color: TOKENS.rustDark, background: `${TOKENS.rust}12`, padding: "6px 10px", borderRadius: 6 }}>
              Estoque atual: {selected.quantity} {selected.unit}. A saída deixará o saldo ajustado para zero.
            </div>
          )}
          <Field label="Observação (opcional)">
            <input className="est-input" style={{ width: "100%" }} value={note} onChange={(e) => setNote(e.target.value)} placeholder="Ex: pedido de reposição, ajuste de inventário..." />
          </Field>
        </div>

        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 20 }}>
          <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={onClose}>Cancelar</button>
          <button type="submit" className="est-btn" style={{ background: isIn ? TOKENS.teal : TOKENS.rust, color: "#fff" }} disabled={isIn && !source}>Confirmar</button>
        </div>
      </form>
    </div>
  );
}

function MovementEditModal({ movement, linkedMovement, products, onSave, onDelete, onClose }) {
  const isTransfer = !!linkedMovement;
  const cityProducts = products.filter((p) => p.city === movement.city);
  const [productId, setProductId] = useState(movement.productId);
  const [type, setType] = useState(movement.type);
  const [quantity, setQuantity] = useState(movement.quantity);
  const [source, setSource] = useState(movement.source || "");
  const [note, setNote] = useState(movement.note || "");
  const isIn = type === "entrada";
  const selected = cityProducts.find((p) => p.id === productId);

  function submit(e) {
    e.preventDefault();
    if (!productId || Number(quantity) <= 0) return;
    if (isIn && !isTransfer && !source) return;
    onSave({
      productId,
      type,
      quantity: Number(quantity),
      note,
      ...(isIn && !isTransfer ? { source } : {}),
    });
  }

  return (
    <div className="est-modal-overlay" onClick={onClose}>
      <form className="est-modal" onClick={(e) => e.stopPropagation()} onSubmit={submit}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16 }}>
            Editar movimentação
          </div>
          <button type="button" onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={18} /></button>
        </div>

        {isTransfer && (
          <div style={{ fontSize: 12, color: TOKENS.inkLight, background: TOKENS.paperDark, borderRadius: 8, padding: "8px 10px", marginBottom: 12 }}>
            Essa movimentação faz parte de uma transferência
            {movement.type === "saida" ? ` (${movement.city} → ${linkedMovement.city})` : ` (${linkedMovement.city} → ${movement.city})`}.
            Produto e tipo ficam fixos — só a quantidade muda, nos dois lados junto.
          </div>
        )}

        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <Field label="Produto">
            <select
              className="est-input"
              style={{ width: "100%" }}
              value={productId}
              disabled={isTransfer}
              onChange={(e) => setProductId(e.target.value)}
            >
              {cityProducts.map((p) => <option key={p.id} value={p.id}>{p.name} ({p.sku})</option>)}
            </select>
          </Field>
          <Field label="Tipo">
            <select
              className="est-input"
              style={{ width: "100%" }}
              value={type}
              disabled={isTransfer}
              onChange={(e) => setType(e.target.value)}
            >
              <option value="entrada">Entrada</option>
              <option value="saida">Saída</option>
            </select>
          </Field>
          <Field label={`Quantidade${selected ? ` (${selected.unit})` : ""}`}>
            <input className="est-input" style={{ width: "100%" }} type="number" min="1" value={quantity} onChange={(e) => setQuantity(e.target.value)} required />
          </Field>
          {isIn && !isTransfer && (
            <Field label="Origem da entrada">
              <select className="est-input" style={{ width: "100%" }} value={source} onChange={(e) => setSource(e.target.value)} required>
                <option value="" disabled>Selecione…</option>
                <option value="local">Comprado localmente</option>
                <option value="matriz">Veio da matriz (Umuarama)</option>
              </select>
            </Field>
          )}
          <Field label="Observação">
            <input className="est-input" style={{ width: "100%" }} value={note} onChange={(e) => setNote(e.target.value)} />
          </Field>
        </div>

        <div style={{ display: "flex", gap: 8, justifyContent: "space-between", marginTop: 20 }}>
          <button type="button" className="est-btn" style={{ background: `${TOKENS.rust}18`, color: TOKENS.rustDark }} onClick={onDelete}>
            <Trash2 size={14} /> Apagar
          </button>
          <div style={{ display: "flex", gap: 8 }}>
            <button type="button" className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={onClose}>Cancelar</button>
            <button type="submit" className="est-btn" style={{ background: isIn ? TOKENS.teal : TOKENS.rust, color: "#fff" }} disabled={isIn && !isTransfer && !source}>Salvar alterações</button>
          </div>
        </div>
      </form>
    </div>
  );
}

// Remove acentos, baixa a caixa e tira espaços extras — usado para "casar"
// nomes de produtos da planilha com os já cadastrados, mesmo com pequenas
// diferenças de digitação/acentuação.
function normalize(str) {
  return String(str || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim()
    .replace(/\s+/g, " ");
}

// Tenta achar, dentre os cabeçalhos da planilha, qual coluna corresponde
// a produto/sku/quantidade/observação, testando termos comuns em pt-BR.
function detectColumns(headers) {
  const norm = headers.map((h) => normalize(h));
  const find = (candidates) => {
    const idx = norm.findIndex((h) => candidates.some((c) => h.includes(c)));
    return idx === -1 ? null : headers[idx];
  };
  return {
    name: find(["produto", "nome", "item", "descricao", "material"]),
    sku: find(["sku", "codigo", "cod."]),
    quantity: find(["quant", "qtd", "qtde"]),
    unit: find(["unid", "un."]),
    note: find(["obs", "observ", "nota"]),
  };
}

function parseQuantity(raw) {
  if (raw === null || raw === undefined || raw === "") return NaN;
  if (typeof raw === "number") return raw;
  const cleaned = String(raw).replace(/\./g, "").replace(",", ".").replace(/[^0-9.\-]/g, "");
  return Number(cleaned);
}

function ImportModal({ products, city, onImport, onClose }) {
  const fileRef = useRef(null);
  const [fileName, setFileName] = useState(null);
  const [rows, setRows] = useState(null); // linhas processadas e prontas para revisão
  const [error, setError] = useState(null);
  const [busy, setBusy] = useState(false);

  function reset() {
    setFileName(null);
    setRows(null);
    setError(null);
  }

  async function handleFile(file) {
    setError(null);
    setBusy(true);
    setFileName(file.name);
    try {
      const buf = await file.arrayBuffer();
      const wb = XLSX.read(buf, { type: "array" });
      const firstSheet = wb.Sheets[wb.SheetNames[0]];
      const data = XLSX.utils.sheet_to_json(firstSheet, { defval: "" });

      if (!data.length) {
        setError("A planilha está vazia ou não foi possível ler nenhuma linha.");
        setBusy(false);
        return;
      }

      const headers = Object.keys(data[0]);
      const cols = detectColumns(headers);

      if (!cols.name || !cols.quantity) {
        setError(
          `Não consegui identificar as colunas de produto e/ou quantidade automaticamente. ` +
          `Colunas encontradas: ${headers.join(", ")}. ` +
          `Renomeie a coluna do item para algo como "Produto" e a de quantidade para "Quantidade" e tente novamente.`
        );
        setBusy(false);
        return;
      }

      const bySku = Object.fromEntries(
        products.filter((p) => p.sku).map((p) => [normalize(p.sku), p])
      );
      const byName = Object.fromEntries(products.map((p) => [normalize(p.name), p]));

      const processed = data
        .map((r, i) => {
          const rawName = r[cols.name];
          const rawSku = cols.sku ? r[cols.sku] : "";
          const qty = parseQuantity(r[cols.quantity]);
          const note = cols.note ? String(r[cols.note] || "") : "";
          if (!rawName && !rawSku) return null;

          let match = null;
          if (rawSku && bySku[normalize(rawSku)]) match = bySku[normalize(rawSku)];
          else if (byName[normalize(rawName)]) match = byName[normalize(rawName)];

          return {
            rowIndex: i,
            rawName: String(rawName || "").trim(),
            rawSku: String(rawSku || "").trim(),
            quantity: qty,
            note,
            match,
            include: Number.isFinite(qty) && qty > 0,
            createNew: !match,
            category: CATEGORIES[0],
            unit: cols.unit ? String(r[cols.unit] || "UN").toUpperCase() : "UN",
          };
        })
        .filter(Boolean);

      setRows(processed);
    } catch (e) {
      console.error(e);
      setError("Não foi possível ler este arquivo. Confira se é um .xlsx, .xls ou .csv válido.");
    }
    setBusy(false);
  }

  function updateRow(idx, patch) {
    setRows((rs) => rs.map((r, i) => (i === idx ? { ...r, ...patch } : r)));
  }

  function confirmImport() {
    const toImport = rows.filter((r) => r.include && Number.isFinite(r.quantity) && r.quantity > 0);
    const payload = toImport.map((r) => {
      if (r.match) {
        return { productId: r.match.id, quantity: r.quantity, note: r.note };
      }
      const counters = {};
      const sku = r.rawSku || `IMP-${Date.now()}-${r.rowIndex}`;
      return {
        newProduct: {
          name: r.rawName || sku,
          sku,
          category: r.category,
          unit: r.unit || "UN",
          quantity: 0,
          minStock: 5,
          unitPrice: 0,
          city,
        },
        quantity: r.quantity,
        note: r.note,
      };
    });
    onImport(payload);
  }

  const readyCount = rows ? rows.filter((r) => r.include && Number.isFinite(r.quantity) && r.quantity > 0).length : 0;
  const matchedCount = rows ? rows.filter((r) => r.match).length : 0;
  const newCount = rows ? rows.filter((r) => !r.match).length : 0;

  return (
    <div className="est-modal-overlay" onClick={onClose}>
      <div className="est-modal" style={{ maxWidth: 720 }} onClick={(e) => e.stopPropagation()}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 4 }}>
          <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, fontSize: 16 }}>
            Importar entrada de materiais
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer", color: TOKENS.inkLight }}><X size={18} /></button>
        </div>
        <p style={{ fontSize: 12, color: TOKENS.inkLight, marginBottom: 16 }}>
          Envie uma planilha (.xlsx, .xls ou .csv) com uma coluna de produto (nome ou SKU) e uma de quantidade.
          Filial de destino para novos itens: <strong>{city}</strong>.
        </p>

        {!rows && (
          <div>
            <div
              onClick={() => fileRef.current?.click()}
              style={{
                border: `1.5px dashed ${TOKENS.line}`, borderRadius: 10, padding: "28px 16px",
                textAlign: "center", cursor: "pointer", background: TOKENS.paper,
              }}
            >
              <FileSpreadsheet size={26} color={TOKENS.inkLight} style={{ marginBottom: 8 }} />
              <div style={{ fontSize: 13, fontWeight: 500 }}>{fileName || "Clique para escolher um arquivo"}</div>
              <div style={{ fontSize: 11, color: TOKENS.inkLight, marginTop: 4 }}>.xlsx, .xls ou .csv</div>
              <input
                ref={fileRef}
                type="file"
                accept=".xlsx,.xls,.csv"
                style={{ display: "none" }}
                onChange={(e) => e.target.files[0] && handleFile(e.target.files[0])}
              />
            </div>
            {busy && <p style={{ fontSize: 12, color: TOKENS.inkLight, marginTop: 10 }}>Lendo planilha…</p>}
            {error && (
              <div style={{ display: "flex", gap: 8, fontSize: 12, color: TOKENS.rustDark, background: `${TOKENS.rust}12`, padding: 10, borderRadius: 8, marginTop: 12 }}>
                <AlertCircle size={16} style={{ flexShrink: 0 }} />
                <span>{error}</span>
              </div>
            )}
          </div>
        )}

        {rows && (
          <div>
            <div style={{ display: "flex", gap: 12, fontSize: 12, color: TOKENS.inkLight, marginBottom: 10, flexWrap: "wrap" }}>
              <span><strong style={{ color: TOKENS.tealDark }}>{matchedCount}</strong> encontrados no estoque</span>
              <span><strong style={{ color: TOKENS.amberDark }}>{newCount}</strong> não encontrados (viram produto novo)</span>
              <span><strong style={{ color: TOKENS.charcoal }}>{readyCount}</strong> serão importados</span>
              <button onClick={reset} style={{ marginLeft: "auto", background: "none", border: "none", color: TOKENS.teal, cursor: "pointer", fontSize: 12 }}>Trocar arquivo</button>
            </div>

            <div style={{ maxHeight: 320, overflowY: "auto", border: `1px solid ${TOKENS.line}`, borderRadius: 8 }}>
              <table className="est-table" style={{ fontSize: 12 }}>
                <thead>
                  <tr>
                    <th style={{ width: 28 }}></th>
                    <th>Produto (planilha)</th>
                    <th>Status</th>
                    <th style={{ width: 90 }}>Qtd.</th>
                    <th>Observação</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((r, i) => (
                    <tr key={i} style={{ opacity: r.include ? 1 : 0.45 }}>
                      <td>
                        <input type="checkbox" checked={r.include} onChange={(e) => updateRow(i, { include: e.target.checked })} />
                      </td>
                      <td>
                        <div style={{ fontWeight: 500 }}>{r.rawName || r.rawSku}</div>
                        {r.rawSku && <div className="est-mono" style={{ fontSize: 10, color: TOKENS.inkLight }}>{r.rawSku}</div>}
                      </td>
                      <td>
                        {r.match ? (
                          <span className="est-stamp" style={{ background: `${TOKENS.teal}18`, color: TOKENS.tealDark, transform: "none" }}>
                            Encontrado · {r.match.sku}
                          </span>
                        ) : (
                          <span className="est-stamp" style={{ background: `${TOKENS.amber}18`, color: TOKENS.amberDark, transform: "none" }}>
                            Produto novo
                          </span>
                        )}
                      </td>
                      <td>
                        <input
                          className="est-input est-mono"
                          type="number"
                          min="0"
                          style={{ width: 80 }}
                          value={Number.isFinite(r.quantity) ? r.quantity : ""}
                          onChange={(e) => updateRow(i, { quantity: e.target.value === "" ? NaN : Number(e.target.value) })}
                        />
                      </td>
                      <td style={{ color: TOKENS.inkLight }}>{r.note || "—"}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: 20 }}>
          <button className="est-btn" style={{ background: TOKENS.paperDark, color: TOKENS.charcoal }} onClick={onClose}>Cancelar</button>
          {rows && (
            <button
              className="est-btn"
              style={{ background: TOKENS.teal, color: "#fff" }}
              disabled={readyCount === 0}
              onClick={confirmImport}
            >
              <Upload size={14} /> Importar {readyCount > 0 ? `(${readyCount})` : ""}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// Alternador compacto "Matriz" / "Local" usado na aba Pedidos pra marcar se
// aquele item deve entrar no pedido enviado à matriz (Umuarama) ou se vai
// ser comprado localmente, por fora.
function OrderSourceToggle({ value, onChange }) {
  const source = value || "matriz";
  return (
    <div style={{ display: "inline-flex", borderRadius: 20, overflow: "hidden", border: `1px solid ${TOKENS.line}`, flexShrink: 0 }}>
      <button
        type="button"
        onClick={() => onChange("matriz")}
        style={{
          fontSize: 11, fontWeight: 600, padding: "5px 10px", border: "none", cursor: "pointer",
          background: source === "matriz" ? TOKENS.ink : "#fff",
          color: source === "matriz" ? "#fff" : TOKENS.inkLight,
        }}
      >
        Matriz
      </button>
      <button
        type="button"
        onClick={() => onChange("local")}
        style={{
          fontSize: 11, fontWeight: 600, padding: "5px 10px", border: "none", cursor: "pointer",
          background: source === "local" ? TOKENS.amber : "#fff",
          color: source === "local" ? TOKENS.ink : TOKENS.inkLight,
        }}
      >
        Local
      </button>
    </div>
  );
}

function Field({ label, children, style }) {
  return (
    <label style={{ display: "flex", flexDirection: "column", gap: 4, fontSize: 12, color: TOKENS.inkLight, fontWeight: 500, ...style }}>
      {label}
      {children}
    </label>
  );
}

// Campo composto de quantidade + "tipo" (UN/CX/PCT/FARDO). Quando o tipo
// escolhido é diferente da unidade-base do produto (que hoje é sempre UN),
// mostra um campo extra pra converter — "quantos UN tem em 1 CX/PCT/FARDO"
// — e uma prévia do total já convertido. Isso permite registrar entradas,
// saídas, transferências e pedidos em caixa/fardo sem que o estoque real
// (guardado sempre na unidade-base do produto) fique bagunçado.
function PackageQtyInput({ baseUnit, quantity, onQuantityChange, unitType, onUnitTypeChange, factor, onFactorChange, label = "Quantidade" }) {
  const needsFactor = unitType !== baseUnit;
  const total = needsFactor
    ? Math.round(((Number(quantity) || 0) * (Number(factor) || 0)) * 100) / 100
    : Number(quantity) || 0;
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      <div style={{ display: "flex", gap: 8 }}>
        <Field label={label} style={{ flex: 1 }}>
          <input className="est-input" style={{ width: "100%" }} type="number" min="0" value={quantity} onChange={(e) => onQuantityChange(e.target.value)} />
        </Field>
        <Field label="Tipo" style={{ width: 96 }}>
          <select className="est-input" style={{ width: "100%" }} value={unitType} onChange={(e) => onUnitTypeChange(e.target.value)}>
            {UNITS.map((u) => <option key={u} value={u}>{u}</option>)}
          </select>
        </Field>
      </div>
      {needsFactor && (
        <>
          <Field label={`Quantos ${baseUnit} tem em 1 ${unitType}?`}>
            <input className="est-input" style={{ width: "100%" }} type="number" min="0" step="0.01" value={factor} onChange={(e) => onFactorChange(e.target.value)} placeholder="ex: 15" />
          </Field>
          <div className="est-mono" style={{ fontSize: 12, color: TOKENS.inkLight }}>
            = <strong style={{ color: TOKENS.charcoal }}>{total}</strong> {baseUnit}
          </div>
        </>
      )}
    </div>
  );
}
